#include "streamworker.h"
#include <opencv2/opencv.hpp>
#include <opencv2/cudacodec.hpp>
#include <opencv2/core/cuda.hpp>
#include <QMutexLocker>
#include <vector>

namespace {

cv::Ptr<cv::cudacodec::VideoReader> openWithNvdec(const std::string& url, int timeoutMs) {
    // cudacodec::createVideoReader 에 CAP_PROP 파라미터를 넘기면
    // FFmpegVideoSource 가 인식하지 못해 "Unsupported video source" 오류가 발생할 수 있으므로
    // sourceParams 는 빈 벡터로 전달한다.
    const std::vector<int> sourceParams{};

    cv::cudacodec::VideoReaderInitParams params;
    params.allowFrameDrop = true;
    params.udpSource      = false; // RTSP 스트림: false (UDP 직접 소스가 아님)

    cv::Ptr<cv::cudacodec::VideoReader> reader;
    try {
        reader = cv::cudacodec::createVideoReader(url, sourceParams, params);
    } catch (...) {
        return {};
    }

    if (!reader.empty())
        reader->set(cv::cudacodec::BGR);
    return reader;
}

bool openWithFallback(cv::VideoCapture& cap, const std::string& url, int timeoutMs) {
    cap.set(cv::CAP_PROP_HW_ACCELERATION, cv::VIDEO_ACCELERATION_NONE);
    cap.set(cv::CAP_PROP_OPEN_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_READ_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_BUFFERSIZE, 1);
    if (cap.open(url, cv::CAP_FFMPEG)) return true;

    return cap.open(url);
}

} // namespace

StreamWorker::StreamWorker(int cellId, const QString& url, QObject* parent)
    : QThread(parent), m_cellId(cellId), m_url(url) {}

void StreamWorker::stop() {
    m_running = false;
    requestInterruption();
}

bool StreamWorker::takeLatestFrame(QImage& outFrame) {
    QMutexLocker lock(&m_frameMutex);
    if (m_latestFrame.isNull()) return false;
    outFrame = m_latestFrame;
    m_latestFrame = QImage();
    m_notifyPending.store(false, std::memory_order_release);
    return true;
}

void StreamWorker::run() {
    constexpr int READ_TIMEOUT_MS    = 2000;
    constexpr int RECONNECT_DELAY_MS = 3000;

    const auto publishFrame = [this](const cv::Mat& bgrFrame) {
        cv::Mat rgbFrame;
        cv::cvtColor(bgrFrame, rgbFrame, cv::COLOR_BGR2RGB);

        QImage img(rgbFrame.data, rgbFrame.cols, rgbFrame.rows,
                   static_cast<int>(rgbFrame.step),
                   QImage::Format_RGB888);
        {
            QMutexLocker lock(&m_frameMutex);
            m_latestFrame = img.copy();
        }

        // UI 이벤트 큐에는 셀당 프레임 알림 1개만 유지하고, 나머지는 최신 프레임으로 덮어쓴다.
        if (!m_notifyPending.exchange(true, std::memory_order_acq_rel))
            emit frameReady(m_cellId);
    };

    while (!isInterruptionRequested()) {
        emit statusChanged(m_cellId, "연결 중...");

        const std::string url = m_url.toStdString();
        bool usingNvdec = false;

        emit statusChanged(m_cellId, "NVDEC 연결 시도...");
        try {
            auto gpuReader = openWithNvdec(url, READ_TIMEOUT_MS);
            if (!gpuReader.empty()) {
                usingNvdec = true;
                emit statusChanged(m_cellId, m_url + " [NVDEC]");

                cv::cuda::GpuMat gpuFrame;
                cv::Mat cpuFrame;
                while (!isInterruptionRequested()) {
                    if (!gpuReader->nextFrame(gpuFrame) || gpuFrame.empty()) {
                        emit statusChanged(m_cellId, "스트림 끊김 – 재연결...");
                        break;
                    }

                    gpuFrame.download(cpuFrame);
                    if (cpuFrame.empty()) {
                        emit statusChanged(m_cellId, "NVDEC 프레임 변환 실패 – 재연결...");
                        break;
                    }

                    publishFrame(cpuFrame);
                }
            }
        } catch (const cv::Exception& exception) {
            std::cerr << "\nERROR: " << exception.what() << std::endl;
            usingNvdec = false;
        }

        if (!usingNvdec && !isInterruptionRequested()) {
            cv::VideoCapture cap;
            emit statusChanged(m_cellId, "NVDEC 실패 - 일반 디코더 재시도...");
            if (!openWithFallback(cap, url, READ_TIMEOUT_MS)) {
                emit statusChanged(m_cellId, "연결 실패 – 재시도 중...");
            } else {
                emit statusChanged(m_cellId, m_url);

                cv::Mat frame;
                while (!isInterruptionRequested()) {
                    if (!cap.read(frame) || frame.empty()) {
                        emit statusChanged(m_cellId, "스트림 끊김 – 재연결...");
                        break;
                    }

                    publishFrame(frame);
                }
            }

            cap.release();
        }

        // Wait before reconnect
        for (int i = 0; i < (RECONNECT_DELAY_MS / 100) && !isInterruptionRequested(); ++i)
            msleep(100);
    }
}

#include "streamworker.h"
#include <opencv2/opencv.hpp>
#include <opencv2/cudacodec.hpp>
#include <opencv2/core/cuda.hpp>
#include <QMutexLocker>
#include <vector>

namespace {

// cudacodec::FFmpegVideoSource 는 내부적으로 자체 avformat_open_input() 을 호출하며
// AVDictionary 옵션(rtsp_transport, timeout 등)을 전달할 수단이 없다.
// 따라서 rtsp:// / http:// 등 네트워크 URL 에는 사용할 수 없다.
// → 로컬 파일 경로일 때만 시도한다.
bool isLocalFile(const std::string& url) {
    // 스킴이 없거나 드라이브 문자(C:\...)로 시작하면 로컬 파일로 판단
    const std::string lower = [&]{
        std::string s = url;
        std::transform(s.begin(), s.end(), s.begin(), ::tolower);
        return s;
    }();
    if (lower.rfind("rtsp://",  0) == 0) return false;
    if (lower.rfind("rtmp://",  0) == 0) return false;
    if (lower.rfind("http://",  0) == 0) return false;
    if (lower.rfind("https://", 0) == 0) return false;
    if (lower.rfind("udp://",   0) == 0) return false;
    if (lower.rfind("tcp://",   0) == 0) return false;
    return true;
}

cv::Ptr<cv::cudacodec::VideoReader> openWithNvdec(const std::string& url) {
    // 네트워크 스트림은 cudacodec::FFmpegVideoSource 가 AVOptions 를 지원하지 않아
    // "Unsupported video source" 오류가 발생하므로 즉시 포기한다.
    if (!isLocalFile(url))
        return {};

    cv::cudacodec::VideoReaderInitParams params;
    params.allowFrameDrop = true;

    cv::Ptr<cv::cudacodec::VideoReader> reader;
    try {
        reader = cv::cudacodec::createVideoReader(url, {}, params);
    } catch (...) {
        return {};
    }

    if (!reader.empty())
        reader->set(cv::cudacodec::BGR);
    return reader;
}

// VideoCapture 기반 오픈:
//   1순위 – D3D11/DXVA2 GPU 가속 (RTSP 에서도 동작)
//   2순위 – CPU 소프트웨어 디코딩
bool openWithFallback(cv::VideoCapture& cap, const std::string& url, int timeoutMs) {
    // GPU 가속 시도 (D3D11 / DXVA2 / VideoToolbox 등 플랫폼 최적 선택)
    cap.set(cv::CAP_PROP_HW_ACCELERATION, cv::VIDEO_ACCELERATION_ANY);
    cap.set(cv::CAP_PROP_OPEN_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_READ_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_BUFFERSIZE, 1);
    if (cap.open(url, cv::CAP_FFMPEG)) return true;

    // GPU 가속 실패 시 소프트웨어 디코딩으로 재시도
    cap.set(cv::CAP_PROP_HW_ACCELERATION, cv::VIDEO_ACCELERATION_NONE);
    cap.set(cv::CAP_PROP_OPEN_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_READ_TIMEOUT_MSEC, timeoutMs);
    cap.set(cv::CAP_PROP_BUFFERSIZE, 1);
    if (cap.open(url, cv::CAP_FFMPEG)) return true;

    return cap.open(url);
}

} // namespace

StreamWorker::StreamWorker(int cellId, const QString& url, QObject* parent)
    : QThread(parent), m_cellId(cellId), m_url(url) {}

void StreamWorker::stop() {
    m_running = false;
    requestInterruption();
}

bool StreamWorker::takeLatestFrame(QImage& outFrame) {
    QMutexLocker lock(&m_frameMutex);
    if (m_latestFrame.isNull()) return false;
    outFrame = m_latestFrame;
    m_latestFrame = QImage();
    m_notifyPending.store(false, std::memory_order_release);
    return true;
}

void StreamWorker::run() {
    constexpr int READ_TIMEOUT_MS    = 2000;
    constexpr int RECONNECT_DELAY_MS = 3000;

    const auto publishFrame = [this](const cv::Mat& bgrFrame) {
        cv::Mat rgbFrame;
        cv::cvtColor(bgrFrame, rgbFrame, cv::COLOR_BGR2RGB);

        QImage img(rgbFrame.data, rgbFrame.cols, rgbFrame.rows,
                   static_cast<int>(rgbFrame.step),
                   QImage::Format_RGB888);
        {
            QMutexLocker lock(&m_frameMutex);
            m_latestFrame = img.copy();
        }

        // UI 이벤트 큐에는 셀당 프레임 알림 1개만 유지하고, 나머지는 최신 프레임으로 덮어쓴다.
        if (!m_notifyPending.exchange(true, std::memory_order_acq_rel))
            emit frameReady(m_cellId);
    };

    while (!isInterruptionRequested()) {
        emit statusChanged(m_cellId, "연결 중...");

        const std::string url = m_url.toStdString();
        bool usingNvdec = false;

        emit statusChanged(m_cellId, "NVDEC 연결 시도...");
        try {
            auto gpuReader = openWithNvdec(url, READ_TIMEOUT_MS);
            if (!gpuReader.empty()) {
                usingNvdec = true;
                emit statusChanged(m_cellId, m_url + " [NVDEC]");

                cv::cuda::GpuMat gpuFrame;
                cv::Mat cpuFrame;
                while (!isInterruptionRequested()) {
                    if (!gpuReader->nextFrame(gpuFrame) || gpuFrame.empty()) {
                        emit statusChanged(m_cellId, "스트림 끊김 – 재연결...");
                        break;
                    }

                    gpuFrame.download(cpuFrame);
                    if (cpuFrame.empty()) {
                        emit statusChanged(m_cellId, "NVDEC 프레임 변환 실패 – 재연결...");
                        break;
                    }

                    publishFrame(cpuFrame);
                }
            }
        } catch (const cv::Exception& exception) {
            std::cerr << "\nERROR: " << exception.what() << std::endl;
            usingNvdec = false;
        }

        if (!usingNvdec && !isInterruptionRequested()) {
            cv::VideoCapture cap;
            emit statusChanged(m_cellId, "NVDEC 실패 - 일반 디코더 재시도...");
            if (!openWithFallback(cap, url, READ_TIMEOUT_MS)) {
                emit statusChanged(m_cellId, "연결 실패 – 재시도 중...");
            } else {
                emit statusChanged(m_cellId, m_url);

                cv::Mat frame;
                while (!isInterruptionRequested()) {
                    if (!cap.read(frame) || frame.empty()) {
                        emit statusChanged(m_cellId, "스트림 끊김 – 재연결...");
                        break;
                    }

                    publishFrame(frame);
                }
            }

            cap.release();
        }

        // Wait before reconnect
        for (int i = 0; i < (RECONNECT_DELAY_MS / 100) && !isInterruptionRequested(); ++i)
            msleep(100);
    }
}

#include "videocell.h"
#include <QApplication>
#include <QPainter>
#include <QInputDialog>
#include <QMenu>
#include <QDrag>
#include <QMouseEvent>
#include <QContextMenuEvent>
#include <QResizeEvent>
#include <QSizePolicy>
#include <QDragEnterEvent>
#include <QDragLeaveEvent>
#include <QDropEvent>
#include <QMimeData>
#include <QHash>
#include <QUrl>

#ifdef Q_OS_WIN
#include <qt_windows.h>
#include <d2d1.h>
#include <d2d1helper.h>
#include <dwrite.h>
#include <wrl/client.h>
#endif

static constexpr int STATUS_H = 14;
static constexpr const char* CELL_DRAG_MIME = "application/x-rtsp-viewer-cell-id";

namespace {

QRectF aspectFitRect(const QSizeF& src, const QSizeF& dst) {
    if (src.isEmpty() || dst.isEmpty())
        return {};

    const qreal scale = qMin(dst.width() / src.width(), dst.height() / src.height());
    const QSizeF scaled(src.width() * scale, src.height() * scale);
    return {
        (dst.width() - scaled.width()) * 0.5,
        (dst.height() - scaled.height()) * 0.5,
        scaled.width(),
        scaled.height()
    };
}

QRect videoRectFor(const QSize& size) {
    const int h = qMax(1, size.height() - STATUS_H);
    return {0, 0, size.width(), h};
}

QRect statusRectFor(const QSize& size) {
    const int y = qMax(0, size.height() - STATUS_H);
    return {0, y, size.width(), STATUS_H};
}

QRect statusLabelRectFor(const QSize& size) {
    constexpr int borderInset = 4;
    constexpr int topInset = 2;
    constexpr int bottomInset = 4;
    return statusRectFor(size).adjusted(borderInset, topInset, -borderInset, -bottomInset);
}

bool isDirectRenderableFormat(const QImage::Format format) {
    static const QHash<QImage::Format, bool> directFormats{
        {QImage::Format_ARGB32,                 true},
        {QImage::Format_RGB32,                  true},
        {QImage::Format_ARGB32_Premultiplied,   true}
    };
    return directFormats.value(format, false);
}

#ifdef Q_OS_WIN

using Microsoft::WRL::ComPtr;

static D2D1_SIZE_U nativeClientPixelSize(const HWND hwnd) {
    RECT rc{};
    if (!hwnd || !GetClientRect(hwnd, &rc))
        return D2D1::SizeU(1, 1);

    const auto w = static_cast<UINT32>(qMax<LONG>(1, rc.right - rc.left));
    const auto h = static_cast<UINT32>(qMax<LONG>(1, rc.bottom - rc.top));
    return D2D1::SizeU(w, h);
}

static D2D1_COLOR_F toD2D(const QColor& color) {
    return D2D1::ColorF(color.redF(), color.greenF(), color.blueF(), color.alphaF());
}

#endif

} // namespace

#ifdef Q_OS_WIN
struct VideoCell::RenderState {
    ComPtr<ID2D1Factory> factory;
    ComPtr<IDWriteFactory> dwriteFactory;
    ComPtr<ID2D1HwndRenderTarget> renderTarget;
    ComPtr<ID2D1Bitmap> frameBitmap;
    ComPtr<ID2D1SolidColorBrush> activeBorderBrush;
    ComPtr<ID2D1SolidColorBrush> inactiveBorderBrush;
    ComPtr<ID2D1SolidColorBrush> dragBorderBrush;
    ComPtr<ID2D1SolidColorBrush> placeholderBrush;
    ComPtr<ID2D1SolidColorBrush> channelTextBrush;
    ComPtr<ID2D1SolidColorBrush> plusTextBrush;
};
#endif

VideoCell::VideoCell(int cellId, QWidget* parent)
    : QWidget(parent), m_cellId(cellId)
{
    setMinimumSize(160, 120);
    setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Expanding);
    setAttribute(Qt::WA_OpaquePaintEvent);
    setAcceptDrops(true);

#ifdef Q_OS_WIN
    setAttribute(Qt::WA_NativeWindow);
    setAttribute(Qt::WA_PaintOnScreen);
    setAttribute(Qt::WA_NoSystemBackground);
    (void)winId();
#endif

    m_statusLabel = new QLabel(this);
    m_statusLabel->setAlignment(Qt::AlignLeft | Qt::AlignVCenter);
    m_statusLabel->setAutoFillBackground(true);
    m_statusLabel->setAttribute(Qt::WA_StyledBackground, true);
    m_statusLabel->setStyleSheet(
        "QLabel { background-color: #000000; color: #dddddd;"
        "         font-size: 9px; padding-left: 4px; }");
    m_statusLabel->setGeometry(statusLabelRectFor(size()));
    m_statusLabel->hide();
}

VideoCell::~VideoCell() {
    discardRenderResources();
}

// ── public slots ──────────────────────────────────────────────

void VideoCell::activate(const QString& url) {
    m_active = true;
    m_url    = url;
    m_frame = {};
    m_bitmapDirty = true;
    setStatus("연결 중...");
    update();
}

void VideoCell::deactivate() {
    m_active = false;
    m_url.clear();
    m_frame = {};
    m_bitmapDirty = true;
    setStatus(QString());
    update();
}

void VideoCell::updateFrame(const QImage& frame) {
    if (isDirectRenderableFormat(frame.format())) {
        m_frame = frame;
    } else {
        m_frame = frame.convertToFormat(QImage::Format_ARGB32);
    }
    m_bitmapDirty = true;
    update();
}

void VideoCell::setStatus(const QString& status) {
    if (status.isEmpty()) {
        m_statusLabel->clear();
        m_statusLabel->hide();
        update(statusRectFor(size()));
        return;
    }
    m_statusLabel->setText(" " + status);
    m_statusLabel->setGeometry(statusLabelRectFor(size()));
    m_statusLabel->show();
    m_statusLabel->raise();
    update(statusRectFor(size()));
}

// ── events ────────────────────────────────────────────────────

void VideoCell::dragEnterEvent(QDragEnterEvent* ev) {
    const auto* md = ev->mimeData();
    if (md->hasFormat(CELL_DRAG_MIME) || md->hasText() || md->hasUrls()) {
        ev->acceptProposedAction();
        m_dragHover = true;
        update();
        return;
    }
    ev->ignore();
}

void VideoCell::dragMoveEvent(QDragMoveEvent* ev) {
    const auto* md = ev->mimeData();
    if (md->hasFormat(CELL_DRAG_MIME) || md->hasText() || md->hasUrls()) {
        ev->acceptProposedAction();
        return;
    }
    ev->ignore();
}

void VideoCell::dragLeaveEvent(QDragLeaveEvent* ev) {
    Q_UNUSED(ev);
    if (m_dragHover) {
        m_dragHover = false;
        update();
    }
}

void VideoCell::dropEvent(QDropEvent* ev) {
    m_dragHover = false;
    update();

    const auto* md = ev->mimeData();

    if (md->hasFormat(CELL_DRAG_MIME)) {
        bool ok = false;
        const int fromCellId = QString::fromUtf8(md->data(CELL_DRAG_MIME)).toInt(&ok);
        if (ok && fromCellId != m_cellId) {
            emit moveRequested(fromCellId, m_cellId);
            ev->acceptProposedAction();
            return;
        }
    }

    QString url;
    if (md->hasText()) {
        url = md->text().trimmed();
    } else if (md->hasUrls() && !md->urls().isEmpty()) {
        url = md->urls().first().toString().trimmed();
    }

    if (!url.isEmpty()) {
        emit addRequested(m_cellId, url);
        ev->acceptProposedAction();
        return;
    }
    ev->ignore();
}

void VideoCell::mousePressEvent(QMouseEvent* ev) {
    if (ev->button() == Qt::LeftButton)
        m_dragStartPos = ev->pos();
    QWidget::mousePressEvent(ev);
}

void VideoCell::mouseMoveEvent(QMouseEvent* ev) {
    if (!(ev->buttons() & Qt::LeftButton) || !m_active || m_url.isEmpty()) {
        QWidget::mouseMoveEvent(ev);
        return;
    }

    if ((ev->pos() - m_dragStartPos).manhattanLength() < QApplication::startDragDistance()) {
        QWidget::mouseMoveEvent(ev);
        return;
    }

    auto* mime = new QMimeData();
    mime->setText(m_url);
    mime->setData(CELL_DRAG_MIME, QByteArray::number(m_cellId));

    auto* drag = new QDrag(this);
    drag->setMimeData(mime);
    drag->exec(Qt::MoveAction);
}

void VideoCell::resizeEvent(QResizeEvent* ev) {
    QWidget::resizeEvent(ev);
#ifdef Q_OS_WIN
    if (m_renderState && m_renderState->renderTarget) {
        const HWND hwnd = reinterpret_cast<HWND>(winId());
        m_renderState->renderTarget->Resize(nativeClientPixelSize(hwnd));
        m_bitmapDirty = true;
    }
#endif
    m_statusLabel->setGeometry(statusLabelRectFor(ev->size()));
}

QPaintEngine* VideoCell::paintEngine() const {
#ifdef Q_OS_WIN
    return nullptr;
#else
    return QWidget::paintEngine();
#endif
}

void VideoCell::discardRenderResources() {
#ifdef Q_OS_WIN
    m_renderState.reset();
#endif
}

#ifdef Q_OS_WIN
void VideoCell::updateRenderBitmap() {
    if (!m_bitmapDirty || !m_renderState || !m_renderState->renderTarget)
        return;

    m_renderState->frameBitmap.Reset();
    m_bitmapDirty = false;

    if (m_frame.isNull())
        return;

    ID2D1Bitmap* bitmap = nullptr;
    const auto props = D2D1::BitmapProperties(
        D2D1::PixelFormat(DXGI_FORMAT_B8G8R8A8_UNORM, D2D1_ALPHA_MODE_IGNORE));

    const HRESULT hr = m_renderState->renderTarget->CreateBitmap(
        D2D1::SizeU(static_cast<UINT32>(m_frame.width()), static_cast<UINT32>(m_frame.height())),
        m_frame.constBits(),
        static_cast<UINT32>(m_frame.bytesPerLine()),
        props,
        &bitmap);

    if (SUCCEEDED(hr))
        m_renderState->frameBitmap.Attach(bitmap);
}

void VideoCell::renderDirectX() {
    if (size().isEmpty())
        return;

    if (!m_renderState)
        m_renderState = std::make_unique<RenderState>();

    if (!m_renderState->factory) {
        ID2D1Factory* factory = nullptr;
        if (FAILED(D2D1CreateFactory(D2D1_FACTORY_TYPE_SINGLE_THREADED, &factory)))
            return;
        m_renderState->factory.Attach(factory);
    }

    if (!m_renderState->dwriteFactory) {
        IDWriteFactory* dwriteFactory = nullptr;
        const HRESULT hr = DWriteCreateFactory(
            DWRITE_FACTORY_TYPE_SHARED,
            __uuidof(IDWriteFactory),
            reinterpret_cast<IUnknown**>(&dwriteFactory));
        if (FAILED(hr))
            return;
        m_renderState->dwriteFactory.Attach(dwriteFactory);
    }

    if (!m_renderState->renderTarget) {
        const HWND hwnd = reinterpret_cast<HWND>(winId());
        if (!hwnd)
            return;

        ID2D1HwndRenderTarget* renderTarget = nullptr;
        const HRESULT hr = m_renderState->factory->CreateHwndRenderTarget(
            D2D1::RenderTargetProperties(
                D2D1_RENDER_TARGET_TYPE_HARDWARE,
                D2D1::PixelFormat(DXGI_FORMAT_UNKNOWN, D2D1_ALPHA_MODE_IGNORE)),
            D2D1::HwndRenderTargetProperties(
                hwnd,
                nativeClientPixelSize(hwnd)),
            &renderTarget);
        if (FAILED(hr))
            return;

        m_renderState->renderTarget.Attach(renderTarget);

        ID2D1SolidColorBrush* brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(0, 120, 215)), &brush);
        m_renderState->activeBorderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(45, 45, 45)), &brush);
        m_renderState->inactiveBorderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(76, 175, 80)), &brush);
        m_renderState->dragBorderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(Qt::black), &brush);
        m_renderState->placeholderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(80, 80, 80)), &brush);
        m_renderState->channelTextBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(55, 55, 55)), &brush);
        m_renderState->plusTextBrush.Attach(brush);
    }

    updateRenderBitmap();

    auto* rt = m_renderState->renderTarget.Get();
    rt->BeginDraw();
    rt->SetTransform(D2D1::Matrix3x2F::Identity());

    const D2D1_SIZE_F sizeF = rt->GetSize();
    const FLOAT statusTop = qMax(0.0f, sizeF.height - static_cast<FLOAT>(STATUS_H));
    const D2D1_RECT_F videoRect = D2D1::RectF(0.f, 0.f, sizeF.width, statusTop);
    const D2D1_RECT_F statusRect = D2D1::RectF(0.f, statusTop, sizeF.width, sizeF.height);

    rt->Clear(toD2D(Qt::black));
    rt->FillRectangle(statusRect, m_renderState->placeholderBrush.Get());

    if (m_active && m_renderState->frameBitmap) {
        rt->FillRectangle(videoRect, m_renderState->placeholderBrush.Get());

        const auto bitmapSize = m_renderState->frameBitmap->GetSize();
        const QRectF destRect = aspectFitRect(
            QSizeF(bitmapSize.width, bitmapSize.height),
            QSizeF(sizeF.width, qMax(1.0f, statusTop)));

        rt->DrawBitmap(
            m_renderState->frameBitmap.Get(),
            D2D1::RectF(static_cast<FLOAT>(destRect.left()),
                        static_cast<FLOAT>(destRect.top()),
                        static_cast<FLOAT>(destRect.right()),
                        static_cast<FLOAT>(destRect.bottom())),
            1.0f,
            D2D1_BITMAP_INTERPOLATION_MODE_LINEAR);
    } else {
        rt->FillRectangle(videoRect, m_renderState->placeholderBrush.Get());

        const QString channel = QString("CH %1").arg(m_cellId + 1);
        const std::wstring channelText = channel.toStdWString();
        const std::wstring plusText = L"+";

        const FLOAT chFontSize = qMax(10.0f, sizeF.width / 14.0f);
        const FLOAT plusFontSize = qMax(20.0f, sizeF.width / 7.0f);

        ComPtr<IDWriteTextFormat> channelFormat;
        if (SUCCEEDED(m_renderState->dwriteFactory->CreateTextFormat(
                L"Segoe UI", nullptr,
                DWRITE_FONT_WEIGHT_BOLD,
                DWRITE_FONT_STYLE_NORMAL,
                DWRITE_FONT_STRETCH_NORMAL,
                chFontSize,
                L"",
                channelFormat.GetAddressOf()))) {
            channelFormat->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
            channelFormat->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
            rt->DrawTextW(
                channelText.c_str(),
                static_cast<UINT32>(channelText.size()),
                channelFormat.Get(),
                D2D1::RectF(0.f, 0.f, sizeF.width, qMax(1.0f, statusTop - (statusTop / 4.0f))),
                m_renderState->channelTextBrush.Get());
        }

        ComPtr<IDWriteTextFormat> plusFormat;
        if (SUCCEEDED(m_renderState->dwriteFactory->CreateTextFormat(
                L"Segoe UI", nullptr,
                DWRITE_FONT_WEIGHT_NORMAL,
                DWRITE_FONT_STYLE_NORMAL,
                DWRITE_FONT_STRETCH_NORMAL,
                plusFontSize,
                L"",
                plusFormat.GetAddressOf()))) {
            plusFormat->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
            plusFormat->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
            rt->DrawTextW(
                plusText.c_str(),
                static_cast<UINT32>(plusText.size()),
                plusFormat.Get(),
                D2D1::RectF(0.f, statusTop / 5.0f, sizeF.width, statusTop),
                m_renderState->plusTextBrush.Get());
        }
    }

    const FLOAT borderWidth = m_active ? 2.0f : 1.0f;
    auto* borderBrush = m_active ? m_renderState->activeBorderBrush.Get()
                                 : m_renderState->inactiveBorderBrush.Get();
    rt->FillRectangle(D2D1::RectF(0.f, 0.f, sizeF.width, borderWidth), borderBrush);
    rt->FillRectangle(D2D1::RectF(0.f, sizeF.height - borderWidth, sizeF.width, sizeF.height), borderBrush);
    rt->FillRectangle(D2D1::RectF(0.f, 0.f, borderWidth, sizeF.height), borderBrush);
    rt->FillRectangle(D2D1::RectF(sizeF.width - borderWidth, 0.f, sizeF.width, sizeF.height), borderBrush);

    if (m_dragHover) {
        auto* dragBrush = m_renderState->dragBorderBrush.Get();
        constexpr FLOAT dragWidth = 2.0f;
        rt->FillRectangle(D2D1::RectF(0.f, 0.f, sizeF.width, dragWidth), dragBrush);
        rt->FillRectangle(D2D1::RectF(0.f, sizeF.height - dragWidth, sizeF.width, sizeF.height), dragBrush);
        rt->FillRectangle(D2D1::RectF(0.f, 0.f, dragWidth, sizeF.height), dragBrush);
        rt->FillRectangle(D2D1::RectF(sizeF.width - dragWidth, 0.f, sizeF.width, sizeF.height), dragBrush);
    }

    const HRESULT hr = rt->EndDraw();
    if (hr == D2DERR_RECREATE_TARGET) {
        m_bitmapDirty = true;
        discardRenderResources();
    }
}
#endif

void VideoCell::paintEvent(QPaintEvent*) {
#ifdef Q_OS_WIN
    renderDirectX();
#else
    QPainter p(this);
    const QRect videoRect = videoRectFor(size());
    const QRect statusRect = statusRectFor(size());

    if (m_active && !m_frame.isNull()) {
        p.fillRect(videoRect, Qt::black);
        const QRectF dest = aspectFitRect(m_frame.size(), videoRect.size());
        const QRectF translated = dest.translated(videoRect.topLeft());
        p.drawImage(translated, m_frame);
    } else {
        p.fillRect(videoRect, Qt::black);

        QFont f;
        f.setPointSize(qMax(7, width() / 14));
        f.setBold(true);
        p.setFont(f);
        p.setPen(QColor(80, 80, 80));
        p.drawText(videoRect.adjusted(0, 0, 0, -videoRect.height() / 4),
                   Qt::AlignCenter,
                   QString("CH %1").arg(m_cellId + 1));

        QFont pf;
        pf.setPointSize(qMax(14, width() / 7));
        p.setFont(pf);
        p.setPen(QColor(55, 55, 55));
        p.drawText(videoRect.adjusted(0, videoRect.height() / 5, 0, 0),
                   Qt::AlignCenter, "+");
    }

    p.fillRect(statusRect, Qt::black);

    const QColor border = m_active ? QColor(0, 120, 215) : QColor(45, 45, 45);
    const int bw = m_active ? 2 : 1;
    const QRect r = rect();
    if (r.width() > 0 && r.height() > 0) {
        p.fillRect(r.left(), r.top(), r.width(), bw, border);                       // top
        p.fillRect(r.left(), r.bottom() - bw + 1, r.width(), bw, border);           // bottom
        p.fillRect(r.left(), r.top(), bw, r.height(), border);                       // left
        p.fillRect(r.right() - bw + 1, r.top(), bw, r.height(), border);            // right
    }

    if (m_dragHover) {
        p.fillRect(r.left(), r.top(), r.width(), 2, QColor(76, 175, 80));
        p.fillRect(r.left(), r.bottom() - 1, r.width(), 2, QColor(76, 175, 80));
        p.fillRect(r.left(), r.top(), 2, r.height(), QColor(76, 175, 80));
        p.fillRect(r.right() - 1, r.top(), 2, r.height(), QColor(76, 175, 80));
    }
#endif
}

void VideoCell::mouseDoubleClickEvent(QMouseEvent*) {
    if (!m_active) showAddDialog();
}

void VideoCell::contextMenuEvent(QContextMenuEvent* ev) {
    // Native child HWND(VideoCell) 대신 top-level window를 팝업 소유자로 사용한다.
    QWidget* popupParent = window();
    if (!popupParent)
        popupParent = this;

    QMenu menu(popupParent);
    if (!m_active) {
        menu.addAction("스트림 추가...", this, &VideoCell::showAddDialog);
    } else {
        auto* info = menu.addAction(m_url);
        info->setEnabled(false);
        menu.addSeparator();
        menu.addAction("스트림 제거", this,
                       [this]() { emit removeRequested(m_cellId); });
    }
    menu.exec(ev->globalPos());
}

void VideoCell::showAddDialog() {
    bool ok = false;
    // 입력 다이얼로그도 top-level window를 부모로 지정해 native popup 경고를 피한다.
    QWidget* dialogParent = window();
    if (!dialogParent)
        dialogParent = this;

    const QString url = QInputDialog::getText(
        dialogParent,
        QString("채널 %1 – 스트림 추가").arg(m_cellId + 1),
        "RTSP URL:",
        QLineEdit::Normal,
        "rtsp://",
        &ok);
    if (ok && !url.trimmed().isEmpty())
        emit addRequested(m_cellId, url.trimmed());
}

#include "videocell.h"
#include <QApplication>
#include <QPainter>
#include <QInputDialog>
#include <QMenu>
#include <QDrag>
#include <QMouseEvent>
#include <QContextMenuEvent>
#include <QResizeEvent>
#include <QSizePolicy>
#include <QDragEnterEvent>
#include <QDragLeaveEvent>
#include <QDropEvent>
#include <QMimeData>
#include <QHash>
#include <QUrl>

#ifdef Q_OS_WIN
#include <qt_windows.h>
#include <d2d1.h>
#include <d2d1helper.h>
#include <dwrite.h>
#include <wrl/client.h>
#endif

static constexpr int STATUS_H = 14;
static constexpr const char* CELL_DRAG_MIME = "application/x-rtsp-viewer-cell-id";

namespace {

QRectF aspectFitRect(const QSizeF& src, const QSizeF& dst) {
    if (src.isEmpty() || dst.isEmpty())
        return {};

    const qreal scale = qMin(dst.width() / src.width(), dst.height() / src.height());
    const QSizeF scaled(src.width() * scale, src.height() * scale);
    return {
        (dst.width() - scaled.width()) * 0.5,
        (dst.height() - scaled.height()) * 0.5,
        scaled.width(),
        scaled.height()
    };
}

QRect videoRectFor(const QSize& size) {
    const int h = qMax(1, size.height() - STATUS_H);
    return {0, 0, size.width(), h};
}

QRect statusRectFor(const QSize& size) {
    const int y = qMax(0, size.height() - STATUS_H);
    return {0, y, size.width(), STATUS_H};
}

QRect statusLabelRectFor(const QSize& size) {
    constexpr int borderInset = 4;
    constexpr int topInset = 2;
    constexpr int bottomInset = 4;
    return statusRectFor(size).adjusted(borderInset, topInset, -borderInset, -bottomInset);
}

bool isDirectRenderableFormat(const QImage::Format format) {
    static const QHash<QImage::Format, bool> directFormats{
        {QImage::Format_ARGB32,                 true},
        {QImage::Format_RGB32,                  true},
        {QImage::Format_ARGB32_Premultiplied,   true}
    };
    return directFormats.value(format, false);
}

#ifdef Q_OS_WIN

using Microsoft::WRL::ComPtr;

static D2D1_SIZE_U nativeClientPixelSize(const HWND hwnd) {
    RECT rc{};
    if (!hwnd || !GetClientRect(hwnd, &rc))
        return D2D1::SizeU(1, 1);

    const auto w = static_cast<UINT32>(qMax<LONG>(1, rc.right - rc.left));
    const auto h = static_cast<UINT32>(qMax<LONG>(1, rc.bottom - rc.top));
    return D2D1::SizeU(w, h);
}

static D2D1_COLOR_F toD2D(const QColor& color) {
    return D2D1::ColorF(color.redF(), color.greenF(), color.blueF(), color.alphaF());
}

#endif

} // namespace

#ifdef Q_OS_WIN
struct VideoCell::RenderState {
    ComPtr<ID2D1Factory> factory;
    ComPtr<IDWriteFactory> dwriteFactory;
    ComPtr<ID2D1HwndRenderTarget> renderTarget;
    ComPtr<ID2D1Bitmap> frameBitmap;
    ComPtr<ID2D1SolidColorBrush> activeBorderBrush;
    ComPtr<ID2D1SolidColorBrush> inactiveBorderBrush;
    ComPtr<ID2D1SolidColorBrush> dragBorderBrush;
    ComPtr<ID2D1SolidColorBrush> placeholderBrush;
    ComPtr<ID2D1SolidColorBrush> channelTextBrush;
    ComPtr<ID2D1SolidColorBrush> plusTextBrush;
};
#endif

VideoCell::VideoCell(int cellId, QWidget* parent)
    : QWidget(parent), m_cellId(cellId)
{
    setMinimumSize(160, 120);
    setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Expanding);
    setAttribute(Qt::WA_OpaquePaintEvent);
    setAcceptDrops(true);

#ifdef Q_OS_WIN
    setAttribute(Qt::WA_NativeWindow);
    setAttribute(Qt::WA_PaintOnScreen);
    setAttribute(Qt::WA_NoSystemBackground);
    (void)winId();
#endif

    m_statusLabel = new QLabel(this);
    m_statusLabel->setAlignment(Qt::AlignLeft | Qt::AlignVCenter);
    m_statusLabel->setAutoFillBackground(true);
    m_statusLabel->setAttribute(Qt::WA_StyledBackground, true);
    m_statusLabel->setStyleSheet(
        "QLabel { background-color: #000000; color: #dddddd;"
        "         font-size: 9px; padding-left: 4px; }");
    m_statusLabel->setGeometry(statusLabelRectFor(size()));
    m_statusLabel->hide();
}

VideoCell::~VideoCell() {
    discardRenderResources();
}

// ── public slots ──────────────────────────────────────────────

void VideoCell::activate(const QString& url) {
    m_active = true;
    m_url    = url;
    m_frame = {};
    m_bitmapDirty = true;
    setStatus("연결 중...");
    update();
}

void VideoCell::deactivate() {
    m_active = false;
    m_url.clear();
    m_frame = {};
    m_bitmapDirty = true;
    setStatus(QString());
    update();
}

void VideoCell::updateFrame(const QImage& frame) {
    if (isDirectRenderableFormat(frame.format())) {
        m_frame = frame;
    } else {
        m_frame = frame.convertToFormat(QImage::Format_ARGB32);
    }
    m_bitmapDirty = true;
    update();
}

void VideoCell::setStatus(const QString& status) {
    if (status.isEmpty()) {
        m_statusLabel->clear();
        m_statusLabel->hide();
        update(statusRectFor(size()));
        return;
    }
    m_statusLabel->setText(" " + status);
    m_statusLabel->setGeometry(statusLabelRectFor(size()));
    m_statusLabel->show();
    m_statusLabel->raise();
    update(statusRectFor(size()));
}

// ── events ────────────────────────────────────────────────────

void VideoCell::dragEnterEvent(QDragEnterEvent* ev) {
    const auto* md = ev->mimeData();
    if (md->hasFormat(CELL_DRAG_MIME) || md->hasText() || md->hasUrls()) {
        ev->acceptProposedAction();
        m_dragHover = true;
        update();
        return;
    }
    ev->ignore();
}

void VideoCell::dragMoveEvent(QDragMoveEvent* ev) {
    const auto* md = ev->mimeData();
    if (md->hasFormat(CELL_DRAG_MIME) || md->hasText() || md->hasUrls()) {
        ev->acceptProposedAction();
        return;
    }
    ev->ignore();
}

void VideoCell::dragLeaveEvent(QDragLeaveEvent* ev) {
    Q_UNUSED(ev);
    if (m_dragHover) {
        m_dragHover = false;
        update();
    }
}

void VideoCell::dropEvent(QDropEvent* ev) {
    m_dragHover = false;
    update();

    const auto* md = ev->mimeData();

    if (md->hasFormat(CELL_DRAG_MIME)) {
        bool ok = false;
        const int fromCellId = QString::fromUtf8(md->data(CELL_DRAG_MIME)).toInt(&ok);
        if (ok && fromCellId != m_cellId) {
            emit moveRequested(fromCellId, m_cellId);
            ev->acceptProposedAction();
            return;
        }
    }

    QString url;
    if (md->hasText()) {
        url = md->text().trimmed();
    } else if (md->hasUrls() && !md->urls().isEmpty()) {
        url = md->urls().first().toString().trimmed();
    }

    if (!url.isEmpty()) {
        emit addRequested(m_cellId, url);
        ev->acceptProposedAction();
        return;
    }
    ev->ignore();
}

void VideoCell::mousePressEvent(QMouseEvent* ev) {
    if (ev->button() == Qt::LeftButton)
        m_dragStartPos = ev->pos();
    QWidget::mousePressEvent(ev);
}

void VideoCell::mouseMoveEvent(QMouseEvent* ev) {
    if (!(ev->buttons() & Qt::LeftButton) || !m_active || m_url.isEmpty()) {
        QWidget::mouseMoveEvent(ev);
        return;
    }

    if ((ev->pos() - m_dragStartPos).manhattanLength() < QApplication::startDragDistance()) {
        QWidget::mouseMoveEvent(ev);
        return;
    }

    auto* mime = new QMimeData();
    mime->setText(m_url);
    mime->setData(CELL_DRAG_MIME, QByteArray::number(m_cellId));

    auto* drag = new QDrag(this);
    drag->setMimeData(mime);
    drag->exec(Qt::MoveAction);
}

void VideoCell::resizeEvent(QResizeEvent* ev) {
    QWidget::resizeEvent(ev);
#ifdef Q_OS_WIN
    if (m_renderState && m_renderState->renderTarget) {
        const HWND hwnd = reinterpret_cast<HWND>(winId());
        m_renderState->renderTarget->Resize(nativeClientPixelSize(hwnd));
        m_bitmapDirty = true;
    }
#endif
    m_statusLabel->setGeometry(statusLabelRectFor(ev->size()));
}

QPaintEngine* VideoCell::paintEngine() const {
#ifdef Q_OS_WIN
    return nullptr;
#else
    return QWidget::paintEngine();
#endif
}

void VideoCell::discardRenderResources() {
#ifdef Q_OS_WIN
    m_renderState.reset();
#endif
}

#ifdef Q_OS_WIN
void VideoCell::updateRenderBitmap() {
    if (!m_bitmapDirty || !m_renderState || !m_renderState->renderTarget)
        return;

    m_renderState->frameBitmap.Reset();
    m_bitmapDirty = false;

    if (m_frame.isNull())
        return;

    ID2D1Bitmap* bitmap = nullptr;
    const auto props = D2D1::BitmapProperties(
        D2D1::PixelFormat(DXGI_FORMAT_B8G8R8A8_UNORM, D2D1_ALPHA_MODE_IGNORE));

    const HRESULT hr = m_renderState->renderTarget->CreateBitmap(
        D2D1::SizeU(static_cast<UINT32>(m_frame.width()), static_cast<UINT32>(m_frame.height())),
        m_frame.constBits(),
        static_cast<UINT32>(m_frame.bytesPerLine()),
        props,
        &bitmap);

    if (SUCCEEDED(hr))
        m_renderState->frameBitmap.Attach(bitmap);
}

void VideoCell::renderDirectX() {
    if (size().isEmpty())
        return;

    if (!m_renderState)
        m_renderState = std::make_unique<RenderState>();

    if (!m_renderState->factory) {
        ID2D1Factory* factory = nullptr;
        if (FAILED(D2D1CreateFactory(D2D1_FACTORY_TYPE_SINGLE_THREADED, &factory)))
            return;
        m_renderState->factory.Attach(factory);
    }

    if (!m_renderState->dwriteFactory) {
        IDWriteFactory* dwriteFactory = nullptr;
        const HRESULT hr = DWriteCreateFactory(
            DWRITE_FACTORY_TYPE_SHARED,
            __uuidof(IDWriteFactory),
            reinterpret_cast<IUnknown**>(&dwriteFactory));
        if (FAILED(hr))
            return;
        m_renderState->dwriteFactory.Attach(dwriteFactory);
    }

    if (!m_renderState->renderTarget) {
        const HWND hwnd = reinterpret_cast<HWND>(winId());
        if (!hwnd)
            return;

        ID2D1HwndRenderTarget* renderTarget = nullptr;
        const HRESULT hr = m_renderState->factory->CreateHwndRenderTarget(
            D2D1::RenderTargetProperties(
                D2D1_RENDER_TARGET_TYPE_HARDWARE,
                D2D1::PixelFormat(DXGI_FORMAT_UNKNOWN, D2D1_ALPHA_MODE_IGNORE)),
            D2D1::HwndRenderTargetProperties(
                hwnd,
                nativeClientPixelSize(hwnd)),
            &renderTarget);
        if (FAILED(hr))
            return;

        m_renderState->renderTarget.Attach(renderTarget);

        ID2D1SolidColorBrush* brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(0, 120, 215)), &brush);
        m_renderState->activeBorderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(45, 45, 45)), &brush);
        m_renderState->inactiveBorderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(76, 175, 80)), &brush);
        m_renderState->dragBorderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(Qt::black), &brush);
        m_renderState->placeholderBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(80, 80, 80)), &brush);
        m_renderState->channelTextBrush.Attach(brush);

        brush = nullptr;
        m_renderState->renderTarget->CreateSolidColorBrush(toD2D(QColor(55, 55, 55)), &brush);
        m_renderState->plusTextBrush.Attach(brush);
    }

    updateRenderBitmap();

    auto* rt = m_renderState->renderTarget.Get();
    rt->BeginDraw();
    rt->SetTransform(D2D1::Matrix3x2F::Identity());

    const D2D1_SIZE_F sizeF = rt->GetSize();
    const FLOAT statusTop = qMax(0.0f, sizeF.height - static_cast<FLOAT>(STATUS_H));
    const D2D1_RECT_F videoRect = D2D1::RectF(0.f, 0.f, sizeF.width, statusTop);
    const D2D1_RECT_F statusRect = D2D1::RectF(0.f, statusTop, sizeF.width, sizeF.height);

    rt->Clear(toD2D(Qt::black));
    rt->FillRectangle(statusRect, m_renderState->placeholderBrush.Get());

    if (m_active && m_renderState->frameBitmap) {
        rt->FillRectangle(videoRect, m_renderState->placeholderBrush.Get());

        const auto bitmapSize = m_renderState->frameBitmap->GetSize();
        const QRectF destRect = aspectFitRect(
            QSizeF(bitmapSize.width, bitmapSize.height),
            QSizeF(sizeF.width, qMax(1.0f, statusTop)));

        rt->DrawBitmap(
            m_renderState->frameBitmap.Get(),
            D2D1::RectF(static_cast<FLOAT>(destRect.left()),
                        static_cast<FLOAT>(destRect.top()),
                        static_cast<FLOAT>(destRect.right()),
                        static_cast<FLOAT>(destRect.bottom())),
            1.0f,
            D2D1_BITMAP_INTERPOLATION_MODE_LINEAR);
    } else {
        rt->FillRectangle(videoRect, m_renderState->placeholderBrush.Get());

        const QString channel = QString("CH %1").arg(m_cellId + 1);
        const std::wstring channelText = channel.toStdWString();
        const std::wstring plusText = L"+";

        const FLOAT chFontSize = qMax(10.0f, sizeF.width / 14.0f);
        const FLOAT plusFontSize = qMax(20.0f, sizeF.width / 7.0f);

        ComPtr<IDWriteTextFormat> channelFormat;
        if (SUCCEEDED(m_renderState->dwriteFactory->CreateTextFormat(
                L"Segoe UI", nullptr,
                DWRITE_FONT_WEIGHT_BOLD,
                DWRITE_FONT_STYLE_NORMAL,
                DWRITE_FONT_STRETCH_NORMAL,
                chFontSize,
                L"",
                channelFormat.GetAddressOf()))) {
            channelFormat->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
            channelFormat->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
            rt->DrawTextW(
                channelText.c_str(),
                static_cast<UINT32>(channelText.size()),
                channelFormat.Get(),
                D2D1::RectF(0.f, 0.f, sizeF.width, qMax(1.0f, statusTop - (statusTop / 4.0f))),
                m_renderState->channelTextBrush.Get());
        }

        ComPtr<IDWriteTextFormat> plusFormat;
        if (SUCCEEDED(m_renderState->dwriteFactory->CreateTextFormat(
                L"Segoe UI", nullptr,
                DWRITE_FONT_WEIGHT_NORMAL,
                DWRITE_FONT_STYLE_NORMAL,
                DWRITE_FONT_STRETCH_NORMAL,
                plusFontSize,
                L"",
                plusFormat.GetAddressOf()))) {
            plusFormat->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
            plusFormat->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
            rt->DrawTextW(
                plusText.c_str(),
                static_cast<UINT32>(plusText.size()),
                plusFormat.Get(),
                D2D1::RectF(0.f, statusTop / 5.0f, sizeF.width, statusTop),
                m_renderState->plusTextBrush.Get());
        }
    }

    const FLOAT borderWidth = m_active ? 2.0f : 1.0f;
    auto* borderBrush = m_active ? m_renderState->activeBorderBrush.Get()
                                 : m_renderState->inactiveBorderBrush.Get();
    rt->FillRectangle(D2D1::RectF(0.f, 0.f, sizeF.width, borderWidth), borderBrush);
    rt->FillRectangle(D2D1::RectF(0.f, sizeF.height - borderWidth, sizeF.width, sizeF.height), borderBrush);
    rt->FillRectangle(D2D1::RectF(0.f, 0.f, borderWidth, sizeF.height), borderBrush);
    rt->FillRectangle(D2D1::RectF(sizeF.width - borderWidth, 0.f, sizeF.width, sizeF.height), borderBrush);

    if (m_dragHover) {
        auto* dragBrush = m_renderState->dragBorderBrush.Get();
        constexpr FLOAT dragWidth = 2.0f;
        rt->FillRectangle(D2D1::RectF(0.f, 0.f, sizeF.width, dragWidth), dragBrush);
        rt->FillRectangle(D2D1::RectF(0.f, sizeF.height - dragWidth, sizeF.width, sizeF.height), dragBrush);
        rt->FillRectangle(D2D1::RectF(0.f, 0.f, dragWidth, sizeF.height), dragBrush);
        rt->FillRectangle(D2D1::RectF(sizeF.width - dragWidth, 0.f, sizeF.width, sizeF.height), dragBrush);
    }

    const HRESULT hr = rt->EndDraw();
    if (hr == D2DERR_RECREATE_TARGET) {
        m_bitmapDirty = true;
        discardRenderResources();
    }
}
#endif

void VideoCell::paintEvent(QPaintEvent*) {
#ifdef Q_OS_WIN
    renderDirectX();
#else
    QPainter p(this);
    const QRect videoRect = videoRectFor(size());
    const QRect statusRect = statusRectFor(size());

    if (m_active && !m_frame.isNull()) {
        p.fillRect(videoRect, Qt::black);
        const QRectF dest = aspectFitRect(m_frame.size(), videoRect.size());
        const QRectF translated = dest.translated(videoRect.topLeft());
        p.drawImage(translated, m_frame);
    } else {
        p.fillRect(videoRect, Qt::black);

        QFont f;
        f.setPointSize(qMax(7, width() / 14));
        f.setBold(true);
        p.setFont(f);
        p.setPen(QColor(80, 80, 80));
        p.drawText(videoRect.adjusted(0, 0, 0, -videoRect.height() / 4),
                   Qt::AlignCenter,
                   QString("CH %1").arg(m_cellId + 1));

        QFont pf;
        pf.setPointSize(qMax(14, width() / 7));
        p.setFont(pf);
        p.setPen(QColor(55, 55, 55));
        p.drawText(videoRect.adjusted(0, videoRect.height() / 5, 0, 0),
                   Qt::AlignCenter, "+");
    }

    p.fillRect(statusRect, Qt::black);

    const QColor border = m_active ? QColor(0, 120, 215) : QColor(45, 45, 45);
    const int bw = m_active ? 2 : 1;
    const QRect r = rect();
    if (r.width() > 0 && r.height() > 0) {
        p.fillRect(r.left(), r.top(), r.width(), bw, border);                       // top
        p.fillRect(r.left(), r.bottom() - bw + 1, r.width(), bw, border);           // bottom
        p.fillRect(r.left(), r.top(), bw, r.height(), border);                       // left
        p.fillRect(r.right() - bw + 1, r.top(), bw, r.height(), border);            // right
    }

    if (m_dragHover) {
        p.fillRect(r.left(), r.top(), r.width(), 2, QColor(76, 175, 80));
        p.fillRect(r.left(), r.bottom() - 1, r.width(), 2, QColor(76, 175, 80));
        p.fillRect(r.left(), r.top(), 2, r.height(), QColor(76, 175, 80));
        p.fillRect(r.right() - 1, r.top(), 2, r.height(), QColor(76, 175, 80));
    }
#endif
}

void VideoCell::mouseDoubleClickEvent(QMouseEvent*) {
    if (!m_active) showAddDialog();
}

void VideoCell::contextMenuEvent(QContextMenuEvent* ev) {
    // Native child HWND(VideoCell) 대신 top-level window를 팝업 소유자로 사용한다.
    QWidget* popupParent = window();
    if (!popupParent)
        popupParent = this;

    QMenu menu(popupParent);
    if (!m_active) {
        menu.addAction("스트림 추가...", this, &VideoCell::showAddDialog);
    } else {
        auto* info = menu.addAction(m_url);
        info->setEnabled(false);
        menu.addSeparator();
        menu.addAction("스트림 제거", this,
                       [this]() { emit removeRequested(m_cellId); });
    }
    menu.exec(ev->globalPos());
}

void VideoCell::showAddDialog() {
    // 입력 다이얼로그도 top-level window를 부모로 지정해 native popup 경고를 피한다.
    QWidget* dialogParent = window();
    if (!dialogParent)
        dialogParent = this;

    QInputDialog dialog(dialogParent);
    dialog.setInputMode(QInputDialog::TextInput);
    dialog.setWindowTitle(QString("채널 %1 - 스트림 추가").arg(m_cellId + 1));
    dialog.setLabelText("RTSP URL:");
    dialog.setTextEchoMode(QLineEdit::Normal);
    dialog.setTextValue("rtsp://");

    // show 전에 크기를 확정해 Windows의 재배치 경고 가능성을 낮춘다.
    dialog.ensurePolished();
    const QSize targetSize = dialog.sizeHint().expandedTo(dialog.minimumSizeHint());
    dialog.resize(targetSize);

    if (dialog.exec() == QDialog::Accepted) {
        const QString url = dialog.textValue().trimmed();
        if (!url.isEmpty())
            emit addRequested(m_cellId, url);
    }
}

#include "vodpanel.h"

#include "DBManager.h"
#include "vodvideooverlay.h"

#include <QMediaPlayer>
#include <QAudioOutput>
#include <QVideoWidget>
#include <QStackedLayout>
#include <QLabel>
#include <QPushButton>
#include <QVBoxLayout>
#include <QHBoxLayout>
#include <QKeyEvent>
#include <QTimer>
#include <QDir>
#include <QDebug>
#include <QFileInfo>
#include <QDateTime>
#include <QRegularExpression>
#include <QSizePolicy>
#include <QUrl>
#include <algorithm>
#include <limits>

namespace {
constexpr qint64 kPrebufferLeadMs = 1500;  // 파일 경계 1.5초 전부터 다음 파일 선버퍼링
constexpr qint64 kSeekSettleToleranceMs = 250;
constexpr qint64 kReliableDurationThresholdMs = 1000;
constexpr float kActiveVolume = 0.8f;
constexpr float kMuteVolume = 0.0f;
}

// ── 생성자 ─────────────────────────────────────────────────────
VodPanel::VodPanel(const QString& outputRoot, QWidget* parent)
    : QWidget(parent), m_outputRoot(outputRoot)
{
    setFocusPolicy(Qt::StrongFocus);

    // ── 미디어 플레이어 (활성/대기 이중화) ─────────────────────
    auto* videoHost = new QWidget(this);
    m_videoStack = new QStackedLayout(videoHost);
    m_videoStack->setContentsMargins(0, 0, 0, 0);

    for (int i = 0; i < kPlayerCount; ++i) {
        m_players[i] = new QMediaPlayer(this);
        m_audioOutputs[i] = new QAudioOutput(this);
        m_players[i]->setAudioOutput(m_audioOutputs[i]);
        m_audioOutputs[i]->setVolume(i == m_activeSlot ? kActiveVolume : kMuteVolume);

        m_videoWidgets[i] = new QVideoWidget(videoHost);
        m_videoWidgets[i]->setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Expanding);
        m_videoWidgets[i]->setStyleSheet("background: black;");
        m_players[i]->setVideoOutput(m_videoWidgets[i]);
        m_videoStack->addWidget(m_videoWidgets[i]);

        // overlay는 QVideoWidget의 직접 자식으로 올린다.
        // Windows에서 QVideoWidget은 자체 HWND를 가져 형제 위젯을 가리므로,
        // 자식으로 넣어야 비디오 렌더 표면 위에 QPainter가 동작한다.
        m_overlays[i] = new VodVideoOverlay(m_videoWidgets[i]);
        m_overlays[i]->show();
        m_overlays[i]->raise();

        connect(m_players[i], &QMediaPlayer::positionChanged,
                this, [this, i](qint64 posMs) { onPlayerPositionChanged(i, posMs); });
        connect(m_players[i], &QMediaPlayer::mediaStatusChanged,
                this, [this, i](QMediaPlayer::MediaStatus status) { onMediaStatusChanged(i, status); });
        connect(m_players[i], &QMediaPlayer::durationChanged,
                this, [this, i](qint64 duration) { onDurationChanged(i, duration); });
        connect(m_players[i], &QMediaPlayer::playbackStateChanged,
                this, [this, i](QMediaPlayer::PlaybackState state) { onPlaybackStateChanged(i, state); });
    }
    m_videoStack->setCurrentIndex(m_activeSlot);

    // ── 타임라인 ─────────────────────────────────────────────
    m_timeline = new VodTimeline(this);
    m_timeline->setFixedHeight(90);

    // ── 컨트롤 행 ────────────────────────────────────────────
    m_playBtn = new QPushButton("▶  재생", this);
    m_playBtn->setFixedWidth(110);
    m_playBtn->setStyleSheet(
        "QPushButton { background:#1e5080; color:white; border:none;"
        "  border-radius:5px; padding:5px 12px; font-size:13px; }"
        "QPushButton:hover { background:#2a70b0; }"
        "QPushButton:pressed { background:#155070; }");
    connect(m_playBtn, &QPushButton::clicked, this, &VodPanel::togglePlayPause);

    m_timeLabel = new QLabel("----/--/--  --:--:--", this);
    m_timeLabel->setStyleSheet(
        "color:#dddddd; font-size:13px; font-family:monospace;");
    m_timeLabel->setMinimumWidth(220);

    m_infoLabel = new QLabel("좌측 목록에서 카메라를 선택하세요", this);
    m_infoLabel->setStyleSheet("color:#888888; font-size:11px;");
    m_infoLabel->setAlignment(Qt::AlignRight | Qt::AlignVCenter);

    auto* ctrlRow = new QHBoxLayout();
    ctrlRow->setContentsMargins(8, 4, 8, 4);
    ctrlRow->setSpacing(10);
    ctrlRow->addWidget(m_playBtn);
    ctrlRow->addWidget(m_timeLabel);
    ctrlRow->addStretch();
    ctrlRow->addWidget(m_infoLabel);

    // ── 힌트 레이블 ──────────────────────────────────────────
    auto* hintLabel = new QLabel(
        "Space: 재생/일시정지   ←→: ±5초   Ctrl+휠: 줌", this);
    hintLabel->setStyleSheet("color:#555555; font-size:10px;");
    hintLabel->setAlignment(Qt::AlignCenter);

    // ── 전체 레이아웃 ─────────────────────────────────────────
    auto* vbox = new QVBoxLayout(this);
    vbox->setContentsMargins(0, 0, 0, 0);
    vbox->setSpacing(0);
    vbox->addWidget(videoHost, 1);
    vbox->addLayout(ctrlRow);
    vbox->addWidget(m_timeline);
    vbox->addWidget(hintLabel);

    // ── 시그널 연결 ───────────────────────────────────────────
    connect(m_timeline, &VodTimeline::seekRequested,
            this, &VodPanel::onSeekRequested);

}

VodPanel::~VodPanel() = default;

// ── 카메라 로드 ────────────────────────────────────────────────
void VodPanel::loadCamera(int cameraId, int segmentSeconds) {
    resetPlayers();
    m_currentCameraId = cameraId;
    m_segments.clear();
    m_activeSegIdx = kInvalidSegIdx;
    m_prebufferSegIdx = kInvalidSegIdx;
    m_detectionCacheBySegIdx.clear();
    clearAllOverlays();

    const QString cameraDir = QDir::cleanPath(
        m_outputRoot + QString("/camera_%1").arg(cameraId));
    QDir dir(cameraDir);

    if (!dir.exists()) {
        m_infoLabel->setText(
            QString("저장 폴더 없음: camera_%1").arg(cameraId));
        m_timeline->setSegments({});
        updateControls();
        return;
    }

    // ---- 파일 스캔 ----
    // 파일명 패턴: camera_{id}_{yyyyMMdd_HHmmss}_{yyyyMMdd_HHmmss}.mkv
    // 녹화 중인 임시 파일(RECORDING.mkv)은 제외
    const QRegularExpression re(
        QString(R"(^camera_%1_(\d{8}_\d{6})_(\d{8}_\d{6})\.mkv$)").arg(cameraId));

    const QStringList files =
        dir.entryList({"*.mkv"}, QDir::Files, QDir::Name);

    QVector<QPair<qint64, QString>> entries;
    for (const QString& file : files) {
        const auto match = re.match(file);
        if (!match.hasMatch()) continue;   // RECORDING.mkv 등 제외

        QDateTime dtStart = QDateTime::fromString(match.captured(1), "yyyyMMdd_HHmmss");
        QDateTime dtEnd   = QDateTime::fromString(match.captured(2), "yyyyMMdd_HHmmss");
        if (!dtStart.isValid() || !dtEnd.isValid()) continue;

        entries.append({dtStart.toMSecsSinceEpoch(), dir.filePath(file)});
    }
    std::sort(entries.begin(), entries.end());

    // ---- 세그먼트 구성 (종료 시각은 파일명에서 직접 파싱) ----
    const QRegularExpression reEnd(
        QString(R"(^camera_%1_\d{8}_\d{6}_(\d{8}_\d{6})\.mkv$)").arg(cameraId));

    for (const auto& [startMs, filePath] : entries) {
        VodSegment seg;
        seg.startMs  = startMs;
        seg.filePath = filePath;

        const QString fileName = QFileInfo(filePath).fileName();
        const auto mEnd = reEnd.match(fileName);
        if (mEnd.hasMatch()) {
            QDateTime dtEnd = QDateTime::fromString(mEnd.captured(1), "yyyyMMdd_HHmmss");
            seg.endMs = dtEnd.isValid() ? dtEnd.toMSecsSinceEpoch()
                                        : startMs + static_cast<qint64>(segmentSeconds) * 1000;
        } else {
            seg.endMs = startMs + static_cast<qint64>(segmentSeconds) * 1000;
        }
        m_segments.append(seg);
    }

    m_timeline->setSegments(m_segments);

    if (m_segments.isEmpty()) {
        m_infoLabel->setText(
            QString("카메라 %1: 저장된 영상 없음").arg(cameraId));
    } else {
        m_infoLabel->setText(
            QString("카메라 %1  |  영상 %2 개").arg(cameraId).arg(m_segments.size()));
        m_timeline->setPosition(m_segments.first().startMs);
        m_timeLabel->setText(
            QDateTime::fromMSecsSinceEpoch(m_segments.first().startMs)
                .toString("yyyy/MM/dd  HH:mm:ss"));
    }
    updateControls();
}

// ── 키보드 단축키 ──────────────────────────────────────────────
void VodPanel::keyPressEvent(QKeyEvent* event) {
    const qint64 pos = m_timeline->positionMs();
    switch (event->key()) {
    case Qt::Key_Space:
        togglePlayPause();
        event->accept();
        return;
    case Qt::Key_Left:
        onSeekRequested(pos - 5000);
        event->accept();
        return;
    case Qt::Key_Right:
        onSeekRequested(pos + 5000);
        event->accept();
        return;
    default:
        break;
    }
    QWidget::keyPressEvent(event);
}

// ── 탐색 ──────────────────────────────────────────────────────
void VodPanel::onSeekRequested(qint64 absMs) {
    if (m_segments.isEmpty()) return;
    absMs = qBound(m_segments.first().startMs,
                   absMs,
                   m_segments.last().endMs);
    m_timeline->setPosition(absMs);
    const bool wasPlaying =
        m_players[m_activeSlot]->playbackState() == QMediaPlayer::PlayingState;
    playAt(absMs, wasPlaying);
    updateOverlayForAbsMs(absMs);
}

void VodPanel::playAt(qint64 absMs, bool startPlaying) {
    const int idx = findSegmentIndex(absMs);
    if (idx < 0) {
        clearAllOverlays();
        return;
    }

    syncDetectionPrefetch(idx);

    const qint64 offset = absMs - m_segments[idx].startMs;

    if (m_activeSegIdx == idx) {
        // 같은 파일 내 탐색.
        // setPosition() 직후 Qt가 positionChanged(0)을 먼저 발생시키므로,
        // pending을 유지한 채 seek해야 타임라인이 파일 시작으로 튀지 않는다.
        const bool needPlay = startPlaying &&
            m_players[m_activeSlot]->playbackState() != QMediaPlayer::PlayingState;
        m_pendingSeekMs[m_activeSlot]         = offset;
        m_startPlayingOnReady[m_activeSlot]   = needPlay;
        m_players[m_activeSlot]->setPosition(offset);
        prebufferNextSegment();
        return;
    }

    // 이미 다음 파일을 prebuffer해 둔 경우 즉시 스왑
    if (m_prebufferSegIdx == idx) {
        const int oldActive = m_activeSlot;
        const int nextActive = standbySlot();

        // warmup 타이머가 남아 있어도 새 active 슬롯에는 적용되지 않게 무효화한다.
        m_isPrebufferWarmup[nextActive] = false;
        m_isProgrammaticPause[nextActive] = false;
        ++m_warmupGeneration[nextActive];

        switchToSlot(nextActive);
        m_activeSegIdx = idx;
        m_prebufferSegIdx = kInvalidSegIdx;

        m_players[oldActive]->stop();
        m_players[oldActive]->setSource({});

        // duration/decoder 타이밍 이슈로 seek가 무시되는 경우가 있어 pending을 항상 유지한다.
        m_pendingSeekMs[nextActive] = offset;
        m_startPlayingOnReady[nextActive] = startPlaying;
        tryApplyPendingSeek(nextActive);

        prebufferNextSegment();
        return;
    }

    clearPrebuffer();
    loadSegmentToSlot(m_activeSlot, idx, offset, startPlaying);
    prebufferNextSegment();
}

int VodPanel::findSegmentIndex(qint64 absMs) const {
    if (m_segments.isEmpty()) return -1;
    for (int i = 0; i < m_segments.size(); ++i) {
        if (absMs >= m_segments[i].startMs && absMs < m_segments[i].endMs)
            return i;
    }
    if (absMs < m_segments.first().startMs) return 0;
    return m_segments.size() - 1;
}

int VodPanel::standbySlot() const {
    return (m_activeSlot + 1) % kPlayerCount;
}

void VodPanel::resetPlayers() {
    for (int i = 0; i < kPlayerCount; ++i) {
        m_players[i]->stop();
        m_players[i]->setSource({});
        m_pendingSeekMs[i] = -1;
        m_startPlayingOnReady[i] = false;
        m_isPrebufferWarmup[i] = false;
        m_isProgrammaticPause[i] = false;
        ++m_warmupGeneration[i];
        m_audioOutputs[i]->setVolume(i == m_activeSlot ? kActiveVolume : kMuteVolume);
        if (m_overlays[i]) {
            m_overlays[i]->clear();
        }
    }
}

void VodPanel::clearPrebuffer() {
    const int standby = standbySlot();
    m_players[standby]->stop();
    m_players[standby]->setSource({});
    m_pendingSeekMs[standby] = -1;
    m_startPlayingOnReady[standby] = false;
    m_isPrebufferWarmup[standby] = false;
    m_isProgrammaticPause[standby] = false;
    ++m_warmupGeneration[standby];
    m_prebufferSegIdx = kInvalidSegIdx;
    if (m_overlays[standby]) {
        m_overlays[standby]->clear();
    }
}

void VodPanel::switchToSlot(int slot) {
    m_activeSlot = slot;
    if (m_videoStack) {
        m_videoStack->setCurrentIndex(slot);
    }
    for (int i = 0; i < kPlayerCount; ++i) {
        m_audioOutputs[i]->setVolume(i == m_activeSlot ? kActiveVolume : kMuteVolume);
    }
    updateOverlayForAbsMs(m_timeline->positionMs());
}

void VodPanel::loadSegmentToSlot(int slot, int segIdx, qint64 offsetMs, bool startPlaying) {
    if (segIdx < 0 || segIdx >= m_segments.size()) return;

    m_pendingSeekMs[slot] = qMax<qint64>(0, offsetMs);
    m_startPlayingOnReady[slot] = startPlaying;

    // active 슬롯은 warmup을 수행하면 offset이 0으로 되돌아갈 수 있으므로 금지한다.
    const bool isStandbySlot = (slot != m_activeSlot);
    m_isPrebufferWarmup[slot] = isStandbySlot && !startPlaying;
    m_isProgrammaticPause[slot] = false;
    ++m_warmupGeneration[slot];

    m_players[slot]->stop();
    m_players[slot]->setSource(QUrl::fromLocalFile(m_segments[segIdx].filePath));

    if (slot == m_activeSlot) {
        m_activeSegIdx = segIdx;
    } else {
        m_prebufferSegIdx = segIdx;
    }
}

void VodPanel::prebufferNextSegment() {
    if (m_activeSegIdx < 0 || m_activeSegIdx >= m_segments.size()) {
        clearPrebuffer();
        return;
    }

    const int nextSeg = m_activeSegIdx + 1;
    if (nextSeg >= m_segments.size()) {
        clearPrebuffer();
        return;
    }

    if (m_prebufferSegIdx == nextSeg) {
        return;
    }

    const int standby = standbySlot();
    loadSegmentToSlot(standby, nextSeg, 0, false);
}

// ── 플레이어 시그널 처리 ───────────────────────────────────────
void VodPanel::onPlayerPositionChanged(int slot, qint64 posMs) {
    // positionChanged는 seek 확정 여부를 판단할 수 있는 가장 신뢰도 높은 신호다.
    if (m_pendingSeekMs[slot] >= 0) {
        tryApplyPendingSeek(slot);

        // pending seek가 남아있으면(주로 첫 0ms 이벤트) active 타임라인 갱신을 보류한다.
        if (slot == m_activeSlot && m_pendingSeekMs[slot] >= 0) {
            return;
        }
    }

    if (slot != m_activeSlot) return;
    if (m_activeSegIdx < 0 || m_activeSegIdx >= m_segments.size()) return;
    const qint64 absMs = m_segments[m_activeSegIdx].startMs + posMs;
    m_timeline->setPosition(absMs);
    m_timeLabel->setText(
        QDateTime::fromMSecsSinceEpoch(absMs).toString("yyyy/MM/dd  HH:mm:ss"));
    updateOverlayForAbsMs(absMs);

    const qint64 remainingMs = m_segments[m_activeSegIdx].endMs - absMs;
    if (remainingMs <= kPrebufferLeadMs) {
        prebufferNextSegment();
    }
}

void VodPanel::onMediaStatusChanged(int slot, QMediaPlayer::MediaStatus status) {
    if (status == QMediaPlayer::LoadedMedia ||
        status == QMediaPlayer::BufferedMedia ||
        status == QMediaPlayer::BufferingMedia) {
        tryApplyPendingSeek(slot);
    }

    if (slot != m_activeSlot) {
        return;
    }

    if (status == QMediaPlayer::EndOfMedia) {
        const int expectedNextSeg = m_activeSegIdx + 1;
        const int nextSlot = standbySlot();

        // 이미 prebuffer 된 다음 세그먼트가 있으면 화면/오디오만 즉시 스왑
        if (m_prebufferSegIdx == expectedNextSeg &&
            expectedNextSeg >= 0 && expectedNextSeg < m_segments.size()) {
            const int oldActive = m_activeSlot;
            switchToSlot(nextSlot);
            m_activeSegIdx = expectedNextSeg;
            m_prebufferSegIdx = kInvalidSegIdx;

            m_players[oldActive]->stop();
            m_players[oldActive]->setSource({});

            if (m_players[m_activeSlot]->playbackState() != QMediaPlayer::PlayingState) {
                m_players[m_activeSlot]->play();
            }

            prebufferNextSegment();
            updateControls();
            return;
        }

        // prebuffer 실패/미준비 시 기존 방식 폴백
        if (expectedNextSeg >= 0 && expectedNextSeg < m_segments.size()) {
            loadSegmentToSlot(m_activeSlot, expectedNextSeg, 0, true);
            prebufferNextSegment();
        }
    }
}

void VodPanel::onDurationChanged(int slot, qint64 duration) {
    if (duration <= 0) return;

    tryApplyPendingSeek(slot);

    // standby prebuffer 워밍업: 짧게 재생 후 0초로 되돌려 첫 프레임 준비
    if (m_isPrebufferWarmup[slot]) {
        m_isPrebufferWarmup[slot] = false;
        m_isProgrammaticPause[slot] = true;
        const int generation = m_warmupGeneration[slot];
        m_players[slot]->play();
        QTimer::singleShot(120, this, [this, slot, generation]() {
            // slot이 active로 승격됐거나, 새 파일 로드로 generation이 바뀌면 stale 타이머로 간주한다.
            if (slot == m_activeSlot) return;
            if (generation != m_warmupGeneration[slot]) return;
            if (!m_isProgrammaticPause[slot]) return;
            m_players[slot]->pause();
            m_players[slot]->setPosition(0);
            m_isProgrammaticPause[slot] = false;
        });
    }
}

void VodPanel::onPlaybackStateChanged(int slot, QMediaPlayer::PlaybackState) {
    if (m_pendingSeekMs[slot] >= 0) {
        tryApplyPendingSeek(slot);
    }

    if (slot == m_activeSlot) {
        updateOverlayForAbsMs(m_timeline->positionMs());
        updateControls();
    }
}

void VodPanel::tryApplyPendingSeek(int slot)
{
    if (slot < 0 || slot >= kPlayerCount) return;
    if (m_pendingSeekMs[slot] < 0) return;

    auto* player = m_players[slot];
    if (!player) return;

    const qint64 requested = qMax<qint64>(0, m_pendingSeekMs[slot]);
    const qint64 duration = player->duration();
    if (duration <= 0) return;

    const bool durationReliable = (duration >= kReliableDurationThresholdMs);
    const qint64 maxPos = qMax<qint64>(0, duration - 50);
    const qint64 target = durationReliable
                              ? qBound<qint64>(0, requested, maxPos)
                              : requested;
    const qint64 current = player->position();

    // duration이 충분히 신뢰 가능한 시점에 목표 위치에 도달하면 pending을 해제한다.
    // (메타데이터 초기 단계 duration 불안정 시 0ms로 오판 확정되는 문제를 방지)
    if (qAbs(current - target) <= kSeekSettleToleranceMs) {
        if (!durationReliable && requested > kSeekSettleToleranceMs) {
            player->setPosition(target);
            return;
        }

        m_pendingSeekMs[slot] = -1;
        if (m_startPlayingOnReady[slot]) {
            m_startPlayingOnReady[slot] = false;
            player->play();
        }
        return;
    }

    player->setPosition(target);
}

void VodPanel::prefetchDetectionsForSegment(int segIdx)
{
    if (m_currentCameraId <= 0) return;
    if (segIdx < 0 || segIdx >= m_segments.size()) return;
    if (m_detectionCacheBySegIdx.contains(segIdx)) return;

    const auto& seg = m_segments[segIdx];
    const qint64 queryStartMs = seg.startMs;
    const qint64 queryEndMs = qMax(seg.startMs, seg.endMs - 1);

    const auto result = DBManager::instance().listDetectionFramesByRange(
        m_currentCameraId,
        queryStartMs,
        queryEndMs);
    if (!result) {
        qWarning() << "VOD detection 조회 실패:" << result.error()
                   << "camera_id=" << m_currentCameraId
                   << "seg_idx=" << segIdx;
        m_detectionCacheBySegIdx.emplace(segIdx, std::vector<detection_frame_group>{});
        return;
    }

    m_detectionCacheBySegIdx.emplace(segIdx, *result);
}

void VodPanel::syncDetectionPrefetch(int segIdx)
{
    if (segIdx < 0 || segIdx >= m_segments.size()) {
        m_detectionCacheBySegIdx.clear();
        return;
    }

    prefetchDetectionsForSegment(segIdx);
    prefetchDetectionsForSegment(segIdx + 1);

    for (auto it = m_detectionCacheBySegIdx.begin(); it != m_detectionCacheBySegIdx.end();) {
        const bool keepCurrent = (it->first == segIdx);
        const bool keepNext = (it->first == segIdx + 1);
        if (!keepCurrent && !keepNext) {
            it = m_detectionCacheBySegIdx.erase(it);
            continue;
        }
        ++it;
    }
}

const detection_frame_group* VodPanel::findBestFrameForAbsMs(const std::vector<detection_frame_group>& frames,
                                                             qint64 absMs) const
{
    if (frames.empty()) {
        return nullptr;
    }

    const detection_frame_group* bestByFrameUtc = nullptr;
    qint64 bestFrameDelta = std::numeric_limits<qint64>::max();
    for (const auto& frame : frames) {
        const qint64 delta = qAbs(frame.frame.frame_utc_ms - absMs);
        if (delta < bestFrameDelta) {
            bestFrameDelta = delta;
            bestByFrameUtc = &frame;
        }
    }

    if (bestByFrameUtc && bestFrameDelta <= kDetectionMatchToleranceMs) {
        return bestByFrameUtc;
    }

    const detection_frame_group* bestByCaptureUtc = nullptr;
    qint64 bestCaptureDelta = std::numeric_limits<qint64>::max();
    for (const auto& frame : frames) {
        if (frame.frame.capture_utc_ms <= 0) {
            continue;
        }
        const qint64 delta = qAbs(frame.frame.capture_utc_ms - absMs);
        if (delta < bestCaptureDelta) {
            bestCaptureDelta = delta;
            bestByCaptureUtc = &frame;
        }
    }

    if (bestByCaptureUtc && bestCaptureDelta <= kDetectionMatchToleranceMs) {
        return bestByCaptureUtc;
    }

    return nullptr;
}

void VodPanel::updateOverlayForAbsMs(qint64 absMs)
{
    if (m_segments.isEmpty() || m_activeSegIdx < 0 || m_activeSegIdx >= m_segments.size()) {
        clearAllOverlays();
        return;
    }

    const int segIdx = findSegmentIndex(absMs);
    if (segIdx < 0) {
        clearAllOverlays();
        return;
    }

    syncDetectionPrefetch(segIdx);

    for (int i = 0; i < kPlayerCount; ++i) {
        if (i != m_activeSlot && m_overlays[i]) {
            m_overlays[i]->clear();
        }
    }

    auto* overlay = m_overlays[m_activeSlot];
    if (!overlay) {
        return;
    }

    const auto cacheIt = m_detectionCacheBySegIdx.find(segIdx);
    if (cacheIt == m_detectionCacheBySegIdx.end()) {
        overlay->clear();
        return;
    }

    const detection_frame_group* bestFrame = findBestFrameForAbsMs(cacheIt->second, absMs);
    if (!bestFrame) {
        overlay->clear();
        return;
    }

    overlay->setFrameDetections(bestFrame->frame.frame_width,
                                bestFrame->frame.frame_height,
                                bestFrame->detections);
}

void VodPanel::clearAllOverlays()
{
    for (int i = 0; i < kPlayerCount; ++i) {
        if (m_overlays[i]) {
            m_overlays[i]->clear();
        }
    }
}

// ── 재생 / 일시정지 ────────────────────────────────────────────
void VodPanel::togglePlayPause() {
    if (m_segments.isEmpty()) return;
    auto* activePlayer = m_players[m_activeSlot];
    if (activePlayer->playbackState() == QMediaPlayer::PlayingState) {
        activePlayer->pause();
    } else {
        if (activePlayer->source().isEmpty() || m_activeSegIdx < 0) {
            playAt(m_timeline->positionMs(), true);
        } else {
            activePlayer->play();
        }
    }
}

void VodPanel::updateControls() {
    const bool playing =
        m_players[m_activeSlot]->playbackState() == QMediaPlayer::PlayingState;
    m_playBtn->setText(playing ? "⏸  일시정지" : "▶  재생");
}

#include "vodpanel.h"

#include "DBManager.h"
#include "vodvideooverlay.h"

#include <QMediaPlayer>
#include <QAudioOutput>
#include <QVideoWidget>
#include <QStackedLayout>
#include <QLabel>
#include <QPushButton>
#include <QVBoxLayout>
#include <QHBoxLayout>
#include <QKeyEvent>
#include <QTimer>
#include <QDir>
#include <QDebug>
#include <QFileInfo>
#include <QDateTime>
#include <QRegularExpression>
#include <QSizePolicy>
#include <QUrl>
#include <algorithm>
#include <limits>

namespace {
constexpr qint64 kPrebufferLeadMs = 1500;  // 파일 경계 1.5초 전부터 다음 파일 선버퍼링
constexpr qint64 kSeekSettleToleranceMs = 250;
constexpr qint64 kReliableDurationThresholdMs = 1000;
constexpr float kActiveVolume = 0.8f;
constexpr float kMuteVolume = 0.0f;
}

// ── 생성자 ─────────────────────────────────────────────────────
VodPanel::VodPanel(const QString& outputRoot, QWidget* parent)
    : QWidget(parent), m_outputRoot(outputRoot)
{
    setFocusPolicy(Qt::StrongFocus);

    // ── 미디어 플레이어 (활성/대기 이중화) ─────────────────────
    auto* videoHost = new QWidget(this);
    m_videoStack = new QStackedLayout(videoHost);
    m_videoStack->setContentsMargins(0, 0, 0, 0);

    for (int i = 0; i < kPlayerCount; ++i) {
        m_players[i] = new QMediaPlayer(this);
        m_audioOutputs[i] = new QAudioOutput(this);
        m_players[i]->setAudioOutput(m_audioOutputs[i]);
        m_audioOutputs[i]->setVolume(i == m_activeSlot ? kActiveVolume : kMuteVolume);

        m_videoWidgets[i] = new QVideoWidget(videoHost);
        m_videoWidgets[i]->setSizePolicy(QSizePolicy::Expanding, QSizePolicy::Expanding);
        m_videoWidgets[i]->setStyleSheet("background: black;");
        m_players[i]->setVideoOutput(m_videoWidgets[i]);
        m_videoStack->addWidget(m_videoWidgets[i]);

        // overlay는 QVideoWidget의 직접 자식으로 올린다.
        // Windows에서 QVideoWidget은 자체 HWND를 가져 형제 위젯을 가리므로,
        // 자식으로 넣어야 비디오 렌더 표면 위에 QPainter가 동작한다.
        m_overlays[i] = new VodVideoOverlay(m_videoWidgets[i]);
        m_overlays[i]->show();
        m_overlays[i]->raise();

        connect(m_players[i], &QMediaPlayer::positionChanged,
                this, [this, i](qint64 posMs) { onPlayerPositionChanged(i, posMs); });
        connect(m_players[i], &QMediaPlayer::mediaStatusChanged,
                this, [this, i](QMediaPlayer::MediaStatus status) { onMediaStatusChanged(i, status); });
        connect(m_players[i], &QMediaPlayer::durationChanged,
                this, [this, i](qint64 duration) { onDurationChanged(i, duration); });
        connect(m_players[i], &QMediaPlayer::playbackStateChanged,
                this, [this, i](QMediaPlayer::PlaybackState state) { onPlaybackStateChanged(i, state); });
    }
    m_videoStack->setCurrentIndex(m_activeSlot);

    // ── 타임라인 ─────────────────────────────────────────────
    m_timeline = new VodTimeline(this);
    m_timeline->setFixedHeight(90);

    // ── 컨트롤 행 ────────────────────────────────────────────
    m_playBtn = new QPushButton("▶  재생", this);
    m_playBtn->setFixedWidth(110);
    m_playBtn->setStyleSheet(
        "QPushButton { background:#1e5080; color:white; border:none;"
        "  border-radius:5px; padding:5px 12px; font-size:13px; }"
        "QPushButton:hover { background:#2a70b0; }"
        "QPushButton:pressed { background:#155070; }");
    connect(m_playBtn, &QPushButton::clicked, this, &VodPanel::togglePlayPause);

    m_timeLabel = new QLabel("----/--/--  --:--:--", this);
    m_timeLabel->setStyleSheet(
        "color:#dddddd; font-size:13px; font-family:monospace;");
    m_timeLabel->setMinimumWidth(220);

    m_infoLabel = new QLabel("좌측 목록에서 카메라를 선택하세요", this);
    m_infoLabel->setStyleSheet("color:#888888; font-size:11px;");
    m_infoLabel->setAlignment(Qt::AlignRight | Qt::AlignVCenter);

    auto* ctrlRow = new QHBoxLayout();
    ctrlRow->setContentsMargins(8, 4, 8, 4);
    ctrlRow->setSpacing(10);
    ctrlRow->addWidget(m_playBtn);
    ctrlRow->addWidget(m_timeLabel);
    ctrlRow->addStretch();
    ctrlRow->addWidget(m_infoLabel);

    // ── 힌트 레이블 ──────────────────────────────────────────
    auto* hintLabel = new QLabel(
        "Space: 재생/일시정지   ←→: ±5초   Ctrl+휠: 줌", this);
    hintLabel->setStyleSheet("color:#555555; font-size:10px;");
    hintLabel->setAlignment(Qt::AlignCenter);

    // ── 전체 레이아웃 ─────────────────────────────────────────
    auto* vbox = new QVBoxLayout(this);
    vbox->setContentsMargins(0, 0, 0, 0);
    vbox->setSpacing(0);
    vbox->addWidget(videoHost, 1);
    vbox->addLayout(ctrlRow);
    vbox->addWidget(m_timeline);
    vbox->addWidget(hintLabel);

    // ── 시그널 연결 ───────────────────────────────────────────
    connect(m_timeline, &VodTimeline::seekRequested,
            this, &VodPanel::onSeekRequested);

}

VodPanel::~VodPanel() = default;

// ── 카메라 로드 ────────────────────────────────────────────────
void VodPanel::loadCamera(int cameraId, int segmentSeconds) {
    resetPlayers();
    m_currentCameraId = cameraId;
    m_segments.clear();
    m_activeSegIdx = kInvalidSegIdx;
    m_prebufferSegIdx = kInvalidSegIdx;
    m_detectionCacheBySegIdx.clear();
    clearAllOverlays();

    const QString cameraDir = QDir::cleanPath(
        m_outputRoot + QString("/camera_%1").arg(cameraId));
    QDir dir(cameraDir);

    if (!dir.exists()) {
        m_infoLabel->setText(
            QString("저장 폴더 없음: camera_%1").arg(cameraId));
        m_timeline->setSegments({});
        updateControls();
        return;
    }

    // ---- 파일 스캔 ----
    // 파일명 패턴: camera_{id}_{yyyyMMdd_HHmmss}_{yyyyMMdd_HHmmss}.mkv
    // 녹화 중인 임시 파일(RECORDING.mkv)은 제외
    const QRegularExpression re(
        QString(R"(^camera_%1_(\d{8}_\d{6})_(\d{8}_\d{6})\.mkv$)").arg(cameraId));

    const QStringList files =
        dir.entryList({"*.mkv"}, QDir::Files, QDir::Name);

    QVector<QPair<qint64, QString>> entries;
    for (const QString& file : files) {
        const auto match = re.match(file);
        if (!match.hasMatch()) continue;   // RECORDING.mkv 등 제외

        QDateTime dtStart = QDateTime::fromString(match.captured(1), "yyyyMMdd_HHmmss");
        QDateTime dtEnd   = QDateTime::fromString(match.captured(2), "yyyyMMdd_HHmmss");
        if (!dtStart.isValid() || !dtEnd.isValid()) continue;

        entries.append({dtStart.toMSecsSinceEpoch(), dir.filePath(file)});
    }
    std::sort(entries.begin(), entries.end());

    // ---- 세그먼트 구성 (종료 시각은 파일명에서 직접 파싱) ----
    const QRegularExpression reEnd(
        QString(R"(^camera_%1_\d{8}_\d{6}_(\d{8}_\d{6})\.mkv$)").arg(cameraId));

    for (const auto& [startMs, filePath] : entries) {
        VodSegment seg;
        seg.startMs  = startMs;
        seg.filePath = filePath;

        const QString fileName = QFileInfo(filePath).fileName();
        const auto mEnd = reEnd.match(fileName);
        if (mEnd.hasMatch()) {
            QDateTime dtEnd = QDateTime::fromString(mEnd.captured(1), "yyyyMMdd_HHmmss");
            seg.endMs = dtEnd.isValid() ? dtEnd.toMSecsSinceEpoch()
                                        : startMs + static_cast<qint64>(segmentSeconds) * 1000;
        } else {
            seg.endMs = startMs + static_cast<qint64>(segmentSeconds) * 1000;
        }
        m_segments.append(seg);
    }

    m_timeline->setSegments(m_segments);

    if (m_segments.isEmpty()) {
        m_infoLabel->setText(
            QString("카메라 %1: 저장된 영상 없음").arg(cameraId));
    } else {
        m_infoLabel->setText(
            QString("카메라 %1  |  영상 %2 개").arg(cameraId).arg(m_segments.size()));
        m_timeline->setPosition(m_segments.first().startMs);
        m_timeLabel->setText(
            QDateTime::fromMSecsSinceEpoch(m_segments.first().startMs)
                .toString("yyyy/MM/dd  HH:mm:ss"));
    }
    updateControls();
}

// ── 키보드 단축키 ──────────────────────────────────────────────
void VodPanel::keyPressEvent(QKeyEvent* event) {
    const qint64 pos = m_timeline->positionMs();
    switch (event->key()) {
    case Qt::Key_Space:
        togglePlayPause();
        event->accept();
        return;
    case Qt::Key_Left:
        onSeekRequested(pos - 5000);
        event->accept();
        return;
    case Qt::Key_Right:
        onSeekRequested(pos + 5000);
        event->accept();
        return;
    default:
        break;
    }
    QWidget::keyPressEvent(event);
}

// ── 탐색 ──────────────────────────────────────────────────────
void VodPanel::onSeekRequested(qint64 absMs) {
    if (m_segments.isEmpty()) return;
    absMs = qBound(m_segments.first().startMs,
                   absMs,
                   m_segments.last().endMs);
    m_timeline->setPosition(absMs);
    const bool wasPlaying =
        m_players[m_activeSlot]->playbackState() == QMediaPlayer::PlayingState;
    playAt(absMs, wasPlaying);
    updateOverlayForAbsMs(absMs);
}

void VodPanel::playAt(qint64 absMs, bool startPlaying) {
    const int idx = findSegmentIndex(absMs);
    if (idx < 0) {
        clearAllOverlays();
        return;
    }

    syncDetectionPrefetch(idx);

    const qint64 offset = absMs - m_segments[idx].startMs;

    if (m_activeSegIdx == idx) {
        // 같은 파일 내 탐색.
        // setPosition() 직후 Qt가 positionChanged(0)을 먼저 발생시키므로,
        // pending을 유지한 채 seek해야 타임라인이 파일 시작으로 튀지 않는다.
        const bool needPlay = startPlaying &&
            m_players[m_activeSlot]->playbackState() != QMediaPlayer::PlayingState;
        m_pendingSeekMs[m_activeSlot]         = offset;
        m_startPlayingOnReady[m_activeSlot]   = needPlay;
        m_players[m_activeSlot]->setPosition(offset);
        prebufferNextSegment();
        return;
    }

    // 이미 다음 파일을 prebuffer해 둔 경우 즉시 스왑
    if (m_prebufferSegIdx == idx) {
        const int oldActive = m_activeSlot;
        const int nextActive = standbySlot();

        // warmup 타이머가 남아 있어도 새 active 슬롯에는 적용되지 않게 무효화한다.
        m_isPrebufferWarmup[nextActive] = false;
        m_isProgrammaticPause[nextActive] = false;
        ++m_warmupGeneration[nextActive];

        switchToSlot(nextActive);
        m_activeSegIdx = idx;
        m_prebufferSegIdx = kInvalidSegIdx;

        m_players[oldActive]->stop();
        m_players[oldActive]->setSource({});

        // duration/decoder 타이밍 이슈로 seek가 무시되는 경우가 있어 pending을 항상 유지한다.
        m_pendingSeekMs[nextActive] = offset;
        m_startPlayingOnReady[nextActive] = startPlaying;
        tryApplyPendingSeek(nextActive);

        prebufferNextSegment();
        return;
    }

    clearPrebuffer();
    loadSegmentToSlot(m_activeSlot, idx, offset, startPlaying);
    prebufferNextSegment();
}

int VodPanel::findSegmentIndex(qint64 absMs) const {
    if (m_segments.isEmpty()) return -1;
    for (int i = 0; i < m_segments.size(); ++i) {
        if (absMs >= m_segments[i].startMs && absMs < m_segments[i].endMs)
            return i;
    }
    if (absMs < m_segments.first().startMs) return 0;
    return m_segments.size() - 1;
}

int VodPanel::standbySlot() const {
    return (m_activeSlot + 1) % kPlayerCount;
}

void VodPanel::resetPlayers() {
    for (int i = 0; i < kPlayerCount; ++i) {
        m_players[i]->stop();
        m_players[i]->setSource({});
        m_pendingSeekMs[i] = -1;
        m_startPlayingOnReady[i] = false;
        m_isPrebufferWarmup[i] = false;
        m_isProgrammaticPause[i] = false;
        ++m_warmupGeneration[i];
        m_audioOutputs[i]->setVolume(i == m_activeSlot ? kActiveVolume : kMuteVolume);
        if (m_overlays[i]) {
            m_overlays[i]->clear();
        }
    }
}

void VodPanel::clearPrebuffer() {
    const int standby = standbySlot();
    m_players[standby]->stop();
    m_players[standby]->setSource({});
    m_pendingSeekMs[standby] = -1;
    m_startPlayingOnReady[standby] = false;
    m_isPrebufferWarmup[standby] = false;
    m_isProgrammaticPause[standby] = false;
    ++m_warmupGeneration[standby];
    m_prebufferSegIdx = kInvalidSegIdx;
    if (m_overlays[standby]) {
        m_overlays[standby]->clear();
    }
}

void VodPanel::switchToSlot(int slot) {
    m_activeSlot = slot;
    if (m_videoStack) {
        m_videoStack->setCurrentIndex(slot);
    }
    for (int i = 0; i < kPlayerCount; ++i) {
        m_audioOutputs[i]->setVolume(i == m_activeSlot ? kActiveVolume : kMuteVolume);
    }
    updateOverlayForAbsMs(m_timeline->positionMs());
}

void VodPanel::loadSegmentToSlot(int slot, int segIdx, qint64 offsetMs, bool startPlaying) {
    if (segIdx < 0 || segIdx >= m_segments.size()) return;

    m_pendingSeekMs[slot] = qMax<qint64>(0, offsetMs);
    m_startPlayingOnReady[slot] = startPlaying;

    // active 슬롯은 warmup을 수행하면 offset이 0으로 되돌아갈 수 있으므로 금지한다.
    const bool isStandbySlot = (slot != m_activeSlot);
    m_isPrebufferWarmup[slot] = isStandbySlot && !startPlaying;
    m_isProgrammaticPause[slot] = false;
    ++m_warmupGeneration[slot];

    m_players[slot]->stop();
    m_players[slot]->setSource(QUrl::fromLocalFile(m_segments[segIdx].filePath));

    if (slot == m_activeSlot) {
        m_activeSegIdx = segIdx;
    } else {
        m_prebufferSegIdx = segIdx;
    }
}

void VodPanel::prebufferNextSegment() {
    if (m_activeSegIdx < 0 || m_activeSegIdx >= m_segments.size()) {
        clearPrebuffer();
        return;
    }

    const int nextSeg = m_activeSegIdx + 1;
    if (nextSeg >= m_segments.size()) {
        clearPrebuffer();
        return;
    }

    if (m_prebufferSegIdx == nextSeg) {
        return;
    }

    const int standby = standbySlot();
    loadSegmentToSlot(standby, nextSeg, 0, false);
}

// ── 플레이어 시그널 처리 ───────────────────────────────────────
void VodPanel::onPlayerPositionChanged(int slot, qint64 posMs) {
    // positionChanged는 seek 확정 여부를 판단할 수 있는 가장 신뢰도 높은 신호다.
    if (m_pendingSeekMs[slot] >= 0) {
        tryApplyPendingSeek(slot);

        // pending seek가 남아있으면(주로 첫 0ms 이벤트) active 타임라인 갱신을 보류한다.
        if (slot == m_activeSlot && m_pendingSeekMs[slot] >= 0) {
            return;
        }
    }

    if (slot != m_activeSlot) return;
    if (m_activeSegIdx < 0 || m_activeSegIdx >= m_segments.size()) return;
    const qint64 absMs = m_segments[m_activeSegIdx].startMs + posMs;
    m_timeline->setPosition(absMs);
    m_timeLabel->setText(
        QDateTime::fromMSecsSinceEpoch(absMs).toString("yyyy/MM/dd  HH:mm:ss"));
    updateOverlayForAbsMs(absMs);

    const qint64 remainingMs = m_segments[m_activeSegIdx].endMs - absMs;
    if (remainingMs <= kPrebufferLeadMs) {
        prebufferNextSegment();
    }
}

void VodPanel::onMediaStatusChanged(int slot, QMediaPlayer::MediaStatus status) {
    if (status == QMediaPlayer::LoadedMedia ||
        status == QMediaPlayer::BufferedMedia ||
        status == QMediaPlayer::BufferingMedia) {
        tryApplyPendingSeek(slot);
    }

    if (slot != m_activeSlot) {
        return;
    }

    if (status == QMediaPlayer::EndOfMedia) {
        const int expectedNextSeg = m_activeSegIdx + 1;
        const int nextSlot = standbySlot();

        // 이미 prebuffer 된 다음 세그먼트가 있으면 화면/오디오만 즉시 스왑
        if (m_prebufferSegIdx == expectedNextSeg &&
            expectedNextSeg >= 0 && expectedNextSeg < m_segments.size()) {
            const int oldActive = m_activeSlot;
            switchToSlot(nextSlot);
            m_activeSegIdx = expectedNextSeg;
            m_prebufferSegIdx = kInvalidSegIdx;

            m_players[oldActive]->stop();
            m_players[oldActive]->setSource({});

            if (m_players[m_activeSlot]->playbackState() != QMediaPlayer::PlayingState) {
                m_players[m_activeSlot]->play();
            }

            prebufferNextSegment();
            updateControls();
            return;
        }

        // prebuffer 실패/미준비 시 기존 방식 폴백
        if (expectedNextSeg >= 0 && expectedNextSeg < m_segments.size()) {
            loadSegmentToSlot(m_activeSlot, expectedNextSeg, 0, true);
            prebufferNextSegment();
        }
    }
}

void VodPanel::onDurationChanged(int slot, qint64 duration) {
    if (duration <= 0) return;

    tryApplyPendingSeek(slot);

    // standby prebuffer 워밍업: 짧게 재생 후 0초로 되돌려 첫 프레임 준비
    if (m_isPrebufferWarmup[slot]) {
        m_isPrebufferWarmup[slot] = false;
        m_isProgrammaticPause[slot] = true;
        const int generation = m_warmupGeneration[slot];
        m_players[slot]->play();
        QTimer::singleShot(120, this, [this, slot, generation]() {
            // slot이 active로 승격됐거나, 새 파일 로드로 generation이 바뀌면 stale 타이머로 간주한다.
            if (slot == m_activeSlot) return;
            if (generation != m_warmupGeneration[slot]) return;
            if (!m_isProgrammaticPause[slot]) return;
            m_players[slot]->pause();
            m_players[slot]->setPosition(0);
            m_isProgrammaticPause[slot] = false;
        });
    }
}

void VodPanel::onPlaybackStateChanged(int slot, QMediaPlayer::PlaybackState) {
    if (m_pendingSeekMs[slot] >= 0) {
        tryApplyPendingSeek(slot);
    }

    if (slot == m_activeSlot) {
        updateOverlayForAbsMs(m_timeline->positionMs());
        updateControls();
    }
}

void VodPanel::tryApplyPendingSeek(int slot)
{
    if (slot < 0 || slot >= kPlayerCount) return;
    if (m_pendingSeekMs[slot] < 0) return;

    auto* player = m_players[slot];
    if (!player) return;

    const qint64 requested = qMax<qint64>(0, m_pendingSeekMs[slot]);
    const qint64 duration = player->duration();
    if (duration <= 0) return;

    const bool durationReliable = (duration >= kReliableDurationThresholdMs);
    const qint64 maxPos = qMax<qint64>(0, duration - 50);
    const qint64 target = durationReliable
                              ? qBound<qint64>(0, requested, maxPos)
                              : requested;
    const qint64 current = player->position();

    // duration이 충분히 신뢰 가능한 시점에 목표 위치에 도달하면 pending을 해제한다.
    // (메타데이터 초기 단계 duration 불안정 시 0ms로 오판 확정되는 문제를 방지)
    if (qAbs(current - target) <= kSeekSettleToleranceMs) {
        if (!durationReliable && requested > kSeekSettleToleranceMs) {
            player->setPosition(target);
            return;
        }

        m_pendingSeekMs[slot] = -1;
        if (m_startPlayingOnReady[slot]) {
            m_startPlayingOnReady[slot] = false;
            player->play();
        }
        return;
    }

    player->setPosition(target);
}

void VodPanel::prefetchDetectionsForSegment(int segIdx)
{
    if (m_currentCameraId <= 0) return;
    if (segIdx < 0 || segIdx >= m_segments.size()) return;
    if (m_detectionCacheBySegIdx.contains(segIdx)) return;

    const auto& seg = m_segments[segIdx];
    const qint64 queryStartMs = seg.startMs;
    const qint64 queryEndMs = qMax(seg.startMs, seg.endMs - 1);

    const auto result = DBManager::instance().listDetectionFramesByRange(
        m_currentCameraId,
        queryStartMs,
        queryEndMs);
    if (!result) {
        qWarning() << "VOD detection 조회 실패:" << result.error()
                   << "camera_id=" << m_currentCameraId
                   << "seg_idx=" << segIdx;
        m_detectionCacheBySegIdx.emplace(segIdx, std::vector<detection_frame_group>{});
        return;
    }

    m_detectionCacheBySegIdx.emplace(segIdx, *result);
}

void VodPanel::syncDetectionPrefetch(int segIdx)
{
    if (segIdx < 0 || segIdx >= m_segments.size()) {
        m_detectionCacheBySegIdx.clear();
        return;
    }

    prefetchDetectionsForSegment(segIdx);
    prefetchDetectionsForSegment(segIdx + 1);

    for (auto it = m_detectionCacheBySegIdx.begin(); it != m_detectionCacheBySegIdx.end();) {
        const bool keepCurrent = (it->first == segIdx);
        const bool keepNext = (it->first == segIdx + 1);
        if (!keepCurrent && !keepNext) {
            it = m_detectionCacheBySegIdx.erase(it);
            continue;
        }
        ++it;
    }
}

const detection_frame_group* VodPanel::findBestFrameForAbsMs(const std::vector<detection_frame_group>& frames,
                                                             qint64 absMs) const
{
    if (frames.empty()) {
        return nullptr;
    }

    // frame_utc_ms 기준 최근접 프레임 탐색
    const detection_frame_group* bestByFrameUtc = nullptr;
    qint64 bestFrameDelta = std::numeric_limits<qint64>::max();
    for (const auto& frame : frames) {
        const qint64 delta = qAbs(frame.frame.frame_utc_ms - absMs);
        if (delta < bestFrameDelta) {
            bestFrameDelta = delta;
            bestByFrameUtc = &frame;
        }
    }

    // tolerance 이내면 반환
    if (bestByFrameUtc && bestFrameDelta <= kDetectionMatchToleranceMs) {
        qDebug() << "[Overlay] frame_utc_ms match delta=" << bestFrameDelta << "ms";
        return bestByFrameUtc;
    }

    // capture_utc_ms 기준 최근접 프레임 탐색 (fallback)
    const detection_frame_group* bestByCaptureUtc = nullptr;
    qint64 bestCaptureDelta = std::numeric_limits<qint64>::max();
    for (const auto& frame : frames) {
        if (frame.frame.capture_utc_ms <= 0) {
            continue;
        }
        const qint64 delta = qAbs(frame.frame.capture_utc_ms - absMs);
        if (delta < bestCaptureDelta) {
            bestCaptureDelta = delta;
            bestByCaptureUtc = &frame;
        }
    }

    if (bestByCaptureUtc && bestCaptureDelta <= kDetectionMatchToleranceMs) {
        qDebug() << "[Overlay] capture_utc_ms match delta=" << bestCaptureDelta << "ms";
        return bestByCaptureUtc;
    }

    // tolerance 초과 — 녹화/인코딩 지연이 있으므로 최근접 프레임을 무조건 반환한다.
    // (absMs와 frame_utc_ms 기준 최소 delta 비교)
    if (bestByFrameUtc) {
        qDebug() << "[Overlay] tolerance exceeded (" << bestFrameDelta << "ms), returning nearest frame_utc_ms match";
        return bestByFrameUtc;
    }
    return bestByCaptureUtc;
}

void VodPanel::updateOverlayForAbsMs(qint64 absMs)
{
    if (m_segments.isEmpty() || m_activeSegIdx < 0 || m_activeSegIdx >= m_segments.size()) {
        clearAllOverlays();
        return;
    }

    const int segIdx = findSegmentIndex(absMs);
    if (segIdx < 0) {
        clearAllOverlays();
        return;
    }

    syncDetectionPrefetch(segIdx);

    for (int i = 0; i < kPlayerCount; ++i) {
        if (i != m_activeSlot && m_overlays[i]) {
            m_overlays[i]->clear();
        }
    }

    auto* overlay = m_overlays[m_activeSlot];
    if (!overlay) {
        return;
    }

    const auto cacheIt = m_detectionCacheBySegIdx.find(segIdx);
    if (cacheIt == m_detectionCacheBySegIdx.end()) {
        overlay->clear();
        return;
    }

    const detection_frame_group* bestFrame = findBestFrameForAbsMs(cacheIt->second, absMs);
    if (!bestFrame) {
        overlay->clear();
        return;
    }

    overlay->setFrameDetections(bestFrame->frame.frame_width,
                                bestFrame->frame.frame_height,
                                bestFrame->detections);
}

void VodPanel::clearAllOverlays()
{
    for (int i = 0; i < kPlayerCount; ++i) {
        if (m_overlays[i]) {
            m_overlays[i]->clear();
        }
    }
}

// ── 재생 / 일시정지 ────────────────────────────────────────────
void VodPanel::togglePlayPause() {
    if (m_segments.isEmpty()) return;
    auto* activePlayer = m_players[m_activeSlot];
    if (activePlayer->playbackState() == QMediaPlayer::PlayingState) {
        activePlayer->pause();
    } else {
        if (activePlayer->source().isEmpty() || m_activeSegIdx < 0) {
            playAt(m_timeline->positionMs(), true);
        } else {
            activePlayer->play();
        }
    }
}

void VodPanel::updateControls() {
    const bool playing =
        m_players[m_activeSlot]->playbackState() == QMediaPlayer::PlayingState;
    m_playBtn->setText(playing ? "⏸  일시정지" : "▶  재생");
}
